            id: crypto.randomUUID(),
            name: templateName,
            createdAt: new Date().toISOString(),
            layout: layout 
        };
        const updated = [...templates, newTemplate];
        setTemplates(updated);
        localStorage.setItem('rs_templates', JSON.stringify(updated));
        setTemplateName("");
        alert("Şablon kaydedildi.");
