import React, { useState, useMemo, useEffect } from 'react';
import { ActivityType, WorksheetData, Activity, GeneratorOptions, ActivityCategory } from '../types';
import { ACTIVITY_CATEGORIES, ACTIVITIES } from '../constants';
import * as generators from '../services/generators';
import * as offlineGenerators from '../services/offlineGenerators';
import { GeneratorView } from './GeneratorView';
import { statsService } from '../services/statsService';
import { adminService } from '../services/adminService';

interface SidebarProps {
  selectedActivity: ActivityType | null;
  onSelectActivity: (id: ActivityType | null) => void;
  setWorksheetData: (data: WorksheetData) => void;
  setIsLoading: (loading: boolean) => void;
  setError: (error: string | null) => void;
  isLoading: boolean;
  isSidebarOpen: boolean;
  closeSidebar: () => void;
  onAddToHistory: (activityType: ActivityType, data: WorksheetData) => void;
  isExpanded?: boolean;
  onOpenStudentModal?: () => void;
  studentProfile?: any;
  styleSettings?: any;
  onOpenOCR?: () => void;
  onOpenCurriculum?: () => void;
  onOpenReadingStudio?: () => void;
  onOpenMathStudio?: () => void;
  onOpenAlgorithmStudio?: () => void;
}

const toPascalCase = (str: string): string => {
    return str.toLowerCase().split('_').map(word => word.charAt(0).toUpperCase() + word.slice(1)).join('');
};

const Sidebar: React.FC<SidebarProps> = ({
  isSidebarOpen,
  closeSidebar,
  selectedActivity,
  onSelectActivity,
  setWorksheetData,
  setIsLoading,
  setError,
  isLoading,
  onAddToHistory,
  isExpanded = true,
  onOpenStudentModal,
  studentProfile,
  styleSettings,
  onOpenOCR,
  onOpenCurriculum,
  onOpenReadingStudio,
  onOpenMathStudio,
  onOpenAlgorithmStudio
}) => {
  const [openCategoryId, setOpenCategoryId] = useState<string | null>(null);
  const [allActivities, setAllActivities] = useState<Activity[]>(ACTIVITIES);
  const [categories, setCategories] = useState<ActivityCategory[]>(ACTIVITY_CATEGORIES);

  useEffect(() => {
      const loadCustomActivities = async () => {
          try {
              const customActs = await adminService.getAllActivities();
              const mergedActivities = [...ACTIVITIES];
              customActs.forEach(ca => {
                  const index = mergedActivities.findIndex(a => a.id === ca.id);
                  if (index !== -1) mergedActivities[index] = { ...mergedActivities[index], ...ca };
                  else mergedActivities.push(ca);
              });
              setAllActivities(mergedActivities);
              const updatedCategories = ACTIVITY_CATEGORIES.map(cat => ({ ...cat, activities: [...cat.activities] }));
              mergedActivities.forEach(act => {
                  const catId = act.category || 'others';
                  let category = updatedCategories.find(c => c.id === catId);
                  if (!category) {
                      category = { id: catId, title: catId, description: 'Özel Kategori', icon: 'fa-solid fa-folder-open', activities: [], isCustom: true };
                      updatedCategories.push(category);
                  }
                  if (!category.activities.includes(act.id)) category.activities.push(act.id);
              });
              setCategories(updatedCategories);
          } catch (e) { console.error(e); }
      };
      loadCustomActivities();
  }, []);

  const handleGenerate = async (options: GeneratorOptions) => {
    if (!selectedActivity) return;
    setIsLoading(true); setWorksheetData(null); setError(null);
    const currentAct = allActivities.find(a => a.id === selectedActivity);
    try {
        let result: WorksheetData | null = null;
        if (currentAct?.promptId) {
             const promptTemplate = await adminService.getPromptTemplate(currentAct.promptId);
             if (promptTemplate) {
                 const aiResult = await adminService.testPrompt(promptTemplate, {
                     worksheetCount: options.worksheetCount,
                     difficulty: options.difficulty,
                     topic: options.topic || 'Genel',
                     itemCount: options.itemCount
                 });
                 result = Array.isArray(aiResult) ? aiResult : (aiResult?.data ? aiResult.data : [aiResult]);
             }
        } 
        if (!result) {
            const pascalCaseName = toPascalCase(selectedActivity);
            const generatorFunctionName = `generate${pascalCaseName}FromAI`;
            const offlineGeneratorFunctionName = `generateOffline${pascalCaseName}`;
            if (options.mode === 'ai') {
                const onlineGenerator = (generators as any)[generatorFunctionName];
                if (onlineGenerator) result = await onlineGenerator(options);
            }
            if (!result) {
                const offlineGenerator = (offlineGenerators as any)[offlineGeneratorFunctionName];
                if (offlineGenerator) result = await offlineGenerator(options);
            }
        }
        if (result) {
            const labeledResult = result.map((page: any) => ({ ...page, title: page.title || currentAct?.title || 'Etkinlik' }));
            setWorksheetData(labeledResult);
            onAddToHistory(selectedActivity, labeledResult);
            statsService.incrementUsage(selectedActivity).catch(console.error);
        }
    } catch (e: any) { setError(e.message || "Hata oluştu."); } finally { setIsLoading(false); }
  };

  const categorizedActivities = useMemo(() => {
      return categories.map(category => ({
          ...category,
          items: allActivities.filter(act => category.activities.includes(act.id))
      })).filter(c => c.items.length > 0);
  }, [allActivities, categories]);

  return (
    <aside id="tour-sidebar" className={`fixed inset-y-0 left-0 z-30 bg-white/95 dark:bg-zinc-900/95 backdrop-blur-xl border-r border-zinc-200 dark:border-zinc-800 transition-all duration-500 md:relative md:translate-x-0 flex flex-col h-full ${isSidebarOpen ? 'translate-x-0 shadow-2xl' : '-translate-x-full'} ${isExpanded ? 'w-[300px]' : 'w-[70px]'}`}>
        <div className="flex h-full flex-col">
            {selectedActivity ? (
                <GeneratorView activity={allActivities.find(a => a.id === selectedActivity)!} onGenerate={handleGenerate} onBack={() => onSelectActivity(null)} isLoading={isLoading} isExpanded={isExpanded} onOpenStudentModal={onOpenStudentModal} studentProfile={studentProfile} />
            ) : (
                <>
                <div className="flex-shrink-0 h-[56px] flex items-center justify-between px-3 border-b border-zinc-200/50 dark:border-zinc-800/50 bg-zinc-50/30 dark:bg-zinc-800/30">
                    {isExpanded && <div className="relative w-full group"><i className="fa-solid fa-search absolute left-3 top-1/2 -translate-y-1/2 text-zinc-400 text-[10px]"></i><input type="text" placeholder="Etkinlik ara..." className="w-full h-8 pl-8 pr-2 bg-white dark:bg-black/20 border border-zinc-200 dark:border-zinc-700 rounded-lg text-[11px] font-semibold outline-none focus:border-indigo-500/50 transition-all shadow-sm"/></div>}
                    <button onClick={closeSidebar} className="md:hidden ml-2 w-7 h-7 flex items-center justify-center rounded-full hover:bg-zinc-100 text-zinc-500"><i className="fa-solid fa-xmark text-sm"></i></button>
                </div>
                {isExpanded && (
                    <div className="px-4 py-4 grid grid-cols-1 gap-3 shrink-0 border-b border-dashed border-zinc-200 dark:border-zinc-800/50 mb-2">
                        <button onClick={onOpenOCR} className="group w-full relative overflow-hidden bg-white dark:bg-zinc-900 p-3 rounded-2xl border border-zinc-200 dark:border-zinc-700 transition-all flex items-center gap-4 shadow-sm hover:shadow-md hover:border-indigo-300">
                            <div className="w-12 h-12 shrink-0 rounded-xl bg-indigo-50 dark:bg-indigo-900/30 flex items-center justify-center text-indigo-600 dark:text-indigo-400 shadow-sm"><i className="fa-solid fa-wand-magic-sparkles text-xl"></i></div>
                            <div className="flex flex-col items-start"><span className="text-xs font-black text-zinc-700 dark:text-zinc-200 uppercase tracking-widest">AI Dönüştürücü</span><span className="text-[10px] text-zinc-400 font-medium">Materyal Klonlayıcı</span></div>
                        </button>
                        <button onClick={onOpenAlgorithmStudio} className="group w-full relative overflow-hidden bg-white dark:bg-zinc-900 p-3 rounded-2xl border border-zinc-200 dark:border-zinc-700 transition-all flex items-center gap-4 shadow-sm hover:shadow-md hover:border-amber-300">
                            <div className="w-12 h-12 shrink-0 rounded-xl bg-amber-50 dark:bg-amber-900/30 flex items-center justify-center text-amber-600 dark:text-amber-400 shadow-sm"><i className="fa-solid fa-code-fork text-xl"></i></div>
                            <div className="flex flex-col items-start"><span className="text-xs font-black text-zinc-700 dark:text-zinc-200 uppercase tracking-widest">Algoritma Üretici</span><span className="text-[10px] text-zinc-400 font-medium">Mantıksal Akış</span></div>
                        </button>
                        <button onClick={onOpenReadingStudio} className="group w-full relative overflow-hidden bg-white dark:bg-zinc-900 p-3 rounded-2xl border border-zinc-200 dark:border-zinc-700 transition-all flex items-center gap-4 shadow-sm hover:shadow-md hover:border-rose-300">
                            <div className="w-12 h-12 shrink-0 rounded-xl bg-rose-50 dark:bg-rose-900/30 flex items-center justify-center text-rose-600 dark:text-rose-400 shadow-sm"><i className="fa-solid fa-book-open-reader text-xl"></i></div>
                            <div className="flex flex-col items-start"><span className="text-xs font-black text-zinc-700 dark:text-zinc-200 uppercase tracking-widest">Okuma Stüdyosu</span><span className="text-[10px] text-zinc-400 font-medium">Layout Editör</span></div>
                        </button>
                    </div>
                )}
                <nav className="flex-1 overflow-y-auto px-2 py-1 custom-scrollbar space-y-0.5">
                    {categorizedActivities.map((category) => (
                        <div key={category.id}>
                            <button onClick={() => isExpanded && setOpenCategoryId(openCategoryId === category.id ? null : category.id)} className={`w-full flex items-center gap-2 px-2 py-1.5 rounded-lg transition-all ${openCategoryId === category.id && isExpanded ? 'bg-zinc-800 text-white' : 'hover:bg-zinc-100 text-zinc-600 dark:text-zinc-400'}`}>
                                <div className="w-5 h-5 rounded-md flex items-center justify-center text-[10px]"><i className={category.icon}></i></div>
                                {isExpanded && <span className="flex-1 text-left text-[11px] font-bold uppercase truncate">{category.title}</span>}
                            </button>
                            {isExpanded && openCategoryId === category.id && (
                                <div className="pl-3 ml-[11px] border-l border-zinc-200 dark:border-zinc-800 mt-0.5 space-y-0.5">
                                    {category.items.map(activity => (
                                        <button key={activity.id} onClick={() => onSelectActivity(activity.id)} className={`w-full text-left px-3 py-1 rounded-md text-[10px] font-medium transition-all ${selectedActivity === activity.id ? 'bg-indigo-50 text-indigo-700 font-bold' : 'text-zinc-500 hover:text-zinc-900 hover:bg-zinc-50'}`}>{activity.title}</button>
                                    ))}
                                </div>
                            )}
                        </div>
                    ))}
                </nav>
                </>
            )}
        </div>
    </aside>
  );
};

export default Sidebar;

