                     <button onClick={() => handlePrint('print')} className="w-8 h-8 rounded hover:bg-zinc-700 flex items-center justify-center text-zinc-400"><i className="fa-solid fa-print"></i></button>
                </div>
            </div>

            <div className="flex-1 flex overflow-hidden">
                <div className="w-80 h-full bg-[#18181b] border-r border-zinc-800 flex flex-col shrink-0">
                    <div className="flex border-b border-zinc-800">
                        <button onClick={() => setSidebarTab('settings')} className={`flex-1 py-3 text-xs font-bold uppercase ${sidebarTab === 'settings' ? 'text-amber-500 border-b-2 border-amber-500' : 'text-zinc-500'}`}>AYARLAR</button>
                        <button onClick={() => setSidebarTab('templates')} className={`flex-1 py-3 text-xs font-bold uppercase ${sidebarTab === 'templates' ? 'text-amber-500 border-b-2 border-amber-500' : 'text-zinc-500'}`}>ŞABLONLAR</button>
                    </div>
                    <div className="flex-1 overflow-y-auto p-4 space-y-6 custom-scrollbar">
                        {sidebarTab === 'settings' && (
                            <div className="space-y-4">
                                <button onClick={handleGenerate} disabled={isLoading} className="w-full py-4 bg-amber-500 hover:bg-amber-400 text-black rounded-xl font-bold text-sm shadow-lg flex items-center justify-center gap-2">
                                    {isLoading ? <i className="fa-solid fa-circle-notch fa-spin"></i> : <i className="fa-solid fa-wand-magic-sparkles"></i>}
                                    {isLoading ? 'HİKAYE YAZILIYOR...' : 'HİKAYEYİ OLUŞTUR'}
                                </button>
                                <div className="p-4 bg-zinc-800/50 rounded-xl border border-zinc-700">
                                     <h4 className="text-[10px] font-black text-zinc-400 uppercase mb-4 tracking-widest">Şablon Kaydet</h4>
                                     <input type="text" value={templateName} onChange={e => setTemplateName(e.target.value)} placeholder="Şablon Adı..." className="w-full p-2 bg-zinc-900 border border-zinc-700 rounded text-xs mb-2" />
                                     <button onClick={saveTemplate} className="w-full py-2 bg-indigo-600 text-white rounded font-bold text-xs">KAYDET</button>
                                </div>
