                     <div className="flex-1 border-2 border-dashed border-current/30 rounded-xl bg-white/20 relative">
                         <span className="absolute bottom-2 right-2 text-[10px] opacity-50 font-bold uppercase">Çizim Alanı</span>
                     </div>
                 </div>
             );
