import { db } from './firebaseClient';
import * as firestore from "firebase/firestore";

const { collection, addDoc, getDocs, deleteDoc, doc, query, orderBy } = firestore;

export interface ReadingTemplate {
    id: string;
    name: string;
    layout: any[];
    createdAt: string;
}

export const readingTemplateService = {
    saveTemplate: async (userId: string, name: string, layout: any[]): Promise<string> => {
        const colRef = collection(db, "users", userId, "reading_templates");
        // Serialize layout to avoid Firestore deep nesting issues
        const docRef = await addDoc(colRef, {
            name,
            layout: JSON.stringify(layout),
            createdAt: new Date().toISOString()
        });
        return docRef.id;
    },

    getTemplates: async (userId: string): Promise<ReadingTemplate[]> => {
        try {
            const colRef = collection(db, "users", userId, "reading_templates");
            const q = query(colRef, orderBy("createdAt", "desc"));
            const snapshot = await getDocs(q);
            return snapshot.docs.map(d => {
                const data = d.data();
                return {
                    id: d.id,
                    name: data.name,
                    layout: JSON.parse(data.layout),
                    createdAt: data.createdAt
                };
            });
        } catch (e) {
            console.error("Template fetch failed:", e);
            return [];
        }
    },

    deleteTemplate: async (userId: string, templateId: string): Promise<void> => {
        await deleteDoc(doc(db, "users", userId, "reading_templates", templateId));
    }
};

import { db } from './firebaseClient';
import * as firestore from "firebase/firestore";
import { HistoryItem } from '../types';

const { collection, addDoc, getDocs, deleteDoc, doc, query, orderBy, limit, writeBatch } = firestore;

export const historyService = {
    addToHistory: async (userId: string, item: Omit<HistoryItem, 'id'>): Promise<string> => {
        if (!userId || userId === 'guest') return 'temp-' + Date.now();

        const colRef = collection(db, "users", userId, "history");
        const docRef = await addDoc(colRef, {
            activityType: item.activityType,
            title: item.title,
            timestamp: item.timestamp,
            category: item.category,
            // Deeply nested data is stringified for database safety
            data: JSON.stringify(item.data)
        });
        return docRef.id;
    },

    getHistory: async (userId: string): Promise<HistoryItem[]> => {
        if (!userId || userId === 'guest') return [];

        try {
            const colRef = collection(db, "users", userId, "history");
            const q = query(colRef, orderBy("timestamp", "desc"), limit(50));
            const snapshot = await getDocs(q);

            return snapshot.docs.map(d => {
                const data = d.data();
                return {
                    id: d.id,
                    userId: userId,
                    activityType: data.activityType,
                    title: data.title,
                    timestamp: data.timestamp,
                    category: data.category,
                    data: JSON.parse(data.data)
                };
            });
        } catch (e) {
            console.error("History fetch error", e);
            return [];
        }
    },

    deleteHistoryItem: async (userId: string, itemId: string): Promise<void> => {
        await deleteDoc(doc(db, "users", userId, "history", itemId));
    },

    clearHistory: async (userId: string): Promise<void> => {
        const colRef = collection(db, "users", userId, "history");
        const snapshot = await getDocs(colRef);
        const batch = writeBatch(db);
        snapshot.docs.forEach(d => batch.delete(d.ref));
        await batch.commit();
    }
};

import { db } from './firebaseClient';
import * as firestore from "firebase/firestore";
import { SavedWorksheet, SingleWorksheetData, ActivityType, StyleSettings, StudentProfile, CollectionItem, WorkbookSettings } from '../types';

const { collection, addDoc, query, where, getDocs, deleteDoc, doc, updateDoc, increment, getDoc } = firestore;

const serializeData = (data: any): string => {
    try { return JSON.stringify(data); } 
    catch (e) { return "[]"; }
};

const deserializeData = (data: any): any[] => {
    if (typeof data === 'string') {
        try { return JSON.parse(data); } 
        catch (e) { return []; }
    }
    return Array.isArray(data) ? data : [];
};

export const worksheetService = {
    saveWorksheet: async (
        userId: string, 
        name: string, 
        activityType: ActivityType, 
        data: SingleWorksheetData[], 
        icon: string,
        category: { id: string, title: string },
        styleSettings?: StyleSettings,
        studentProfile?: StudentProfile
    ): Promise<SavedWorksheet> => {
        try {
            const payload: any = {
                userId,
                name: name || 'Adsız Etkinlik',
                activityType,
                // Zero data loss: we serialize the entire data array including layouts
                worksheetData: serializeData(data),
                icon: icon || 'fa-solid fa-file',
                category: category || { id: 'uncategorized', title: 'Genel' },
                createdAt: new Date().toISOString(),
            };

            if (styleSettings) payload.styleSettings = styleSettings;
            if (studentProfile) payload.studentProfile = studentProfile;

            const docRef = await addDoc(collection(db, "saved_worksheets"), payload);

            const userRef = doc(db, "users", userId);
            await updateDoc(userRef, { worksheetCount: increment(1) });

            return { id: docRef.id, ...payload, worksheetData: data };
        } catch (error) {
            console.error("Error saving worksheet:", error);
            throw error;
        }
    },

    saveWorkbook: async (
        userId: string, 
        settings: WorkbookSettings, 
        items: CollectionItem[]
    ): Promise<SavedWorksheet> => {
        try {
            const payload: any = {
                userId,
                name: settings.title || 'Adsız Kitapçık',
                activityType: ActivityType.WORKBOOK,
                worksheetData: serializeData([]),
                icon: 'fa-solid fa-book-open-reader',
                category: { id: 'workbook', title: 'Kitapçıklarım' },
                createdAt: new Date().toISOString(),
                workbookItems: serializeData(items),
                workbookSettings: settings
            };

            const docRef = await addDoc(collection(db, "saved_worksheets"), payload);
            const userRef = doc(db, "users", userId);
            await updateDoc(userRef, { worksheetCount: increment(1) });

            return { id: docRef.id, ...payload, worksheetData: [], workbookItems: items };
        } catch (error) {
            console.error("Error saving workbook:", error);
            throw error;
        }
    },

    getUserWorksheets: async (userId: string, page: number, pageSize: number): Promise<{ items: SavedWorksheet[], count: number | null }> => {
        try {
            const q = query(collection(db, "saved_worksheets"), where("userId", "==", userId));
            const querySnapshot = await getDocs(q);
            const items: SavedWorksheet[] = [];
            querySnapshot.forEach((doc) => {
                const data = doc.data() as any;
                if (!data.sharedWith) {
                    items.push({
                        id: doc.id,
                        ...data,
                        worksheetData: deserializeData(data.worksheetData),
                        workbookItems: data.workbookItems ? deserializeData(data.workbookItems) : undefined
                    });
                }
            });
            items.sort((a, b) => new Date(b.createdAt).getTime() - new Date(a.createdAt).getTime());
            return { items, count: items.length };
        } catch (error) {
            return { items: [], count: 0 };
        }
    },

    deleteWorksheet: async (id: string) => {
        await deleteDoc(doc(db, "saved_worksheets", id));
    },

    shareWorksheet: async (worksheet: SavedWorksheet, senderId: string, senderName: string, receiverId: string): Promise<void> => {
        const sharedPayload: any = {
            ...worksheet,
            userId: senderId,
            worksheetData: serializeData(worksheet.worksheetData),
            workbookItems: worksheet.workbookItems ? serializeData(worksheet.workbookItems) : undefined,
            sharedBy: senderId,
            sharedByName: senderName,
            sharedWith: receiverId,
            createdAt: new Date().toISOString(),
        };
        delete sharedPayload.id;
        await addDoc(collection(db, "saved_worksheets"), sharedPayload);
    },

    getSharedWithMe: async (userId: string, page: number, pageSize: number): Promise<{ items: SavedWorksheet[], count: number | null }> => {
        try {
            const q = query(collection(db, "saved_worksheets"), where("sharedWith", "==", userId));
            const querySnapshot = await getDocs(q);
            const items: SavedWorksheet[] = [];
            querySnapshot.forEach((doc) => {
                const data = doc.data() as any;
                items.push({
                    id: doc.id,
                    ...data,
                    worksheetData: deserializeData(data.worksheetData),
                    workbookItems: data.workbookItems ? deserializeData(data.workbookItems) : undefined
                });
            });
            items.sort((a, b) => new Date(b.createdAt).getTime() - new Date(a.createdAt).getTime());
            return { items, count: items.length };
        } catch (error) {
            return { items: [], count: 0 };
        }
    }
};

import { db } from './firebaseClient';
import * as firestore from "firebase/firestore";
import { ActivityType, ActivityStats, Activity } from '../types';
import { ACTIVITIES } from '../constants';
import { authService } from './authService';
import { auth } from './firebaseClient';

const { collection, doc, setDoc, getDocs, updateDoc, increment, getDoc } = firestore;

export const statsService = {
    getAllStats: async (): Promise<ActivityStats[]> => {
        try {
            const querySnapshot = await getDocs(collection(db, "activity_stats"));
            const stats: ActivityStats[] = [];
            querySnapshot.forEach((doc) => {
                const data = doc.data() as any;
                stats.push({
                    activityId: doc.id as ActivityType, 
                    title: data.title,
                    generationCount: data.generationCount,
                    lastGenerated: data.lastGenerated,
                    avgCompletionTime: data.avgCompletionTime || 10
                });
            });
            return stats;
        } catch (e) {
            return [];
        }
    },

    incrementUsage: async (activityId: ActivityType) => {
        try {
            const activity = ACTIVITIES.find(a => a.id === activityId);
            const title = activity ? activity.title : activityId;
            const statRef = doc(db, "activity_stats", activityId);
            const docSnap = await getDoc(statRef);

            if (docSnap.exists()) {
                await updateDoc(statRef, {
                    generationCount: increment(1),
                    lastGenerated: new Date().toISOString()
                });
            } else {
                await setDoc(statRef, {
                    title: title,
                    generationCount: 1,
                    lastGenerated: new Date().toISOString(),
                    avgCompletionTime: 10
                });
            }
        } catch (e) {
            console.warn("Stats error", e);
        }
    },

    getFavorites: (): ActivityType[] => {
        try {
            if (typeof window === 'undefined') return [];
            return JSON.parse(localStorage.getItem('user_favorites') || '[]');
        } catch { return []; }
    },

    toggleFavorite: async (id: ActivityType) => {
        const favs = statsService.getFavorites();
        const newFavs = favs.includes(id) ? favs.filter(f => f !== id) : [...favs, id];
        localStorage.setItem('user_favorites', JSON.stringify(newFavs));

        const currentUser = auth.currentUser;
        if (currentUser) {
            try {
                const userRef = doc(db, "users", currentUser.uid);
                await updateDoc(userRef, { favorites: newFavs });
            } catch (e) {
                console.error("Favorite sync failed", e);
            }
        }
        return newFavs;
    },

    isFavorite: (id: ActivityType) => {
        return statsService.getFavorites().includes(id);
    }
};

