    <div className="space-y-4">
        <div><label className="text-[10px] font-bold text-zinc-400 uppercase block mb-1">Arka Plan</label><div className="flex items-center gap-2 bg-zinc-800 p-2 rounded border border-zinc-700"><input type="color" value={style.backgroundColor === 'transparent' ? '#ffffff' : style.backgroundColor} onChange={e => onUpdate('backgroundColor', e.target.value)} className="w-8 h-8 p-0 border-0 rounded cursor-pointer bg-transparent" /><button onClick={() => onUpdate('backgroundColor', 'transparent')} className={`text-xs px-2 py-1 rounded border transition-colors ml-auto ${style.backgroundColor === 'transparent' ? 'bg-amber-500/20 border-amber-500 text-amber-500 font-bold' : 'bg-zinc-700 border-zinc-600 text-zinc-400'}`}>Şeffaf</button></div></div>
        <div><label className="text-[10px] font-bold text-zinc-400 uppercase block mb-1">Kenarlık</label><div className="grid grid-cols-2 gap-2 mb-2"><select value={style.borderStyle} onChange={e => onUpdate('borderStyle', e.target.value)} className="p-2 bg-zinc-800 border border-zinc-700 rounded text-xs text-zinc-200 outline-none"><option value="solid">Düz</option><option value="dashed">Kesik</option></select><input type="number" min="0" value={style.borderWidth} onChange={e => onUpdate('borderWidth', Number(e.target.value))} className="p-2 bg-zinc-800 border border-zinc-700 rounded text-xs text-zinc-200" placeholder="Kalınlık" /></div><input type="color" value={style.borderColor === 'transparent' ? '#000000' : style.borderColor} onChange={e => onUpdate('borderColor', e.target.value)} className="w-full h-8 p-0 border-0 rounded cursor-pointer bg-zinc-800" /></div>
    </div>
);

const ContentControls = ({ item, onUpdateSpecific }: { item: ActiveComponent, onUpdateSpecific: (data: any) => void }) => {
    if (item.id === 'header') {
        const data = item.specificData || { title: item.customTitle || "HİKAYE BAŞLIĞI", subtitle: "Tarih: ....................", showDate: true };
        return (<div className="space-y-3"><div><label className="text-[10px] font-bold text-zinc-400 uppercase block mb-1">Başlık Metni</label><input type="text" value={data.title} onChange={e => onUpdateSpecific({...data, title: e.target.value})} className="w-full p-2 bg-zinc-800 border border-zinc-700 rounded text-sm font-bold text-zinc-100" /></div><div><label className="text-[10px] font-bold text-zinc-400 uppercase block mb-1">Alt Bilgi / Tarih</label><input type="text" value={data.subtitle} onChange={e => onUpdateSpecific({...data, subtitle: e.target.value})} className="w-full p-2 bg-zinc-800 border border-zinc-700 rounded text-sm text-zinc-100" /></div></div>);
    }
    if (item.id === 'story_block') {
         const data = item.specificData || { text: "Metin bekleniyor...", imagePrompt: "" };
         return (<div className="space-y-3"><label className="text-[10px] font-bold text-zinc-400 uppercase block mb-1">Metin İçeriği</label><textarea value={data.text} onChange={e => onUpdateSpecific({...data, text: e.target.value})} className="w-full h-64 p-2 bg-zinc-800 border border-zinc-700 rounded text-sm leading-relaxed resize-none font-dyslexic text-zinc-200"></textarea></div>);
    }
    if (item.id.startsWith('questions')) {
        const data = item.specificData || { questions: [{text: "Soru 1..."}] };
        const qs = data.questions || [];
        const updateQ = (idx: number, val: string) => { const newQs = [...qs]; newQs[idx] = { ...newQs[idx], text: val }; onUpdateSpecific({...data, questions: newQs}); };
        const addQ = () => onUpdateSpecific({...data, questions: [...qs, {text: "Yeni Soru"}]});
        return (<div className="space-y-3"><div className="flex justify-between items-center mb-2"><label className="text-[10px] font-bold text-zinc-400 uppercase">Sorular</label><button onClick={addQ} className="text-xs bg-amber-500 text-black px-2 py-1 rounded font-bold">+ Ekle</button></div><div className="space-y-2 max-h-64 overflow-y-auto custom-scrollbar">{qs.map((q: any, i: number) => (<div key={i} className="flex gap-2 items-start"><span className="text-xs font-bold w-4 pt-2 text-zinc-500">{i+1}.</span><textarea rows={2} value={q.text} onChange={e => updateQ(i, e.target.value)} className="flex-1 p-2 bg-zinc-800 border border-zinc-700 rounded text-xs resize-none text-zinc-200" /></div>))}</div></div>);
    }
    return <div className="text-zinc-500 text-xs italic p-2 bg-zinc-800 rounded border border-zinc-700">Bu bileşen için özel içerik ayarı yok.</div>;
};

const SettingsStation = ({ item, onUpdate, onClose, onDelete }: { item: ActiveComponent, onUpdate: (updates: Partial<ActiveComponent>) => void, onClose: () => void, onDelete: () => void }) => {
    const [activeTab, setActiveTab] = useState<'content' | 'type' | 'look' | 'layout'>('content');
    const handlePanelClick = (e: React.MouseEvent) => e.stopPropagation();
    const updateStyle = (key: keyof LayoutItem['style'], value: any) => { onUpdate({ style: { ...item.style, [key]: value } }); };
    const updateSpecificData = (data: any) => { onUpdate({ specificData: data }); };
    return (
        <div className="w-80 h-full bg-[#222226] border-l border-zinc-800 shadow-2xl z-50 flex flex-col overflow-hidden animate-in slide-in-from-right-10 duration-300 font-['OpenDyslexic']" onClick={handlePanelClick}>
            <div className="p-4 bg-[#2d2d32] border-b border-zinc-700 flex justify-between items-center shrink-0">
                <h3 className="font-black text-xs uppercase tracking-widest text-zinc-300 flex items-center gap-2"><i className={`fa-solid ${item.icon} text-amber-500`}></i> {item.label}</h3>
                <button onClick={onClose} className="w-6 h-6 rounded-full hover:bg-zinc-700 flex items-center justify-center text-zinc-500 transition-colors"><i className="fa-solid fa-times"></i></button>
            </div>
            <div className="flex border-b border-zinc-700 bg-[#222226] shrink-0">
                {[{ id: 'content', icon: 'fa-pen-to-square', label: 'İçerik' }, { id: 'type', icon: 'fa-font', label: 'Yazı' }, { id: 'look', icon: 'fa-palette', label: 'Stil' }, { id: 'layout', icon: 'fa-ruler-combined', label: 'Düzen' }].map(tab => (
                    <button key={tab.id} onClick={() => setActiveTab(tab.id as any)} className={`flex-1 py-3 text-[9px] font-bold uppercase flex flex-col items-center gap-1 transition-colors ${activeTab === tab.id ? 'text-amber-500 bg-zinc-800 border-b-2 border-amber-500' : 'text-zinc-500 hover:bg-zinc-800 hover:text-zinc-300'}`}><i className={`fa-solid ${tab.icon} text-sm`}></i> {tab.label}</button>
                ))}
            </div>
            <div className="flex-1 overflow-y-auto p-5 custom-scrollbar bg-[#222226]">
                {activeTab === 'content' && <ContentControls item={item} onUpdateSpecific={updateSpecificData} />}
                {activeTab === 'type' && <TypographyControls style={item.style} onUpdate={updateStyle} />}
                {activeTab === 'look' && <AppearanceControls style={item.style} onUpdate={updateStyle} />}
                {activeTab === 'layout' && (
                    <div className="space-y-4 animate-in fade-in">
                        <div className="grid grid-cols-2 gap-3">
                                {['x', 'y', 'w', 'h', 'rotation'].map((key) => (
                                    <div key={key} className="flex items-center bg-zinc-800 border border-zinc-700 rounded-lg px-2 py-1.5 focus-within:ring-1 ring-amber-500">
                                        <span className="text-[10px] font-black text-zinc-500 w-6 uppercase truncate mr-1">{key === 'rotation' ? 'Rot' : key}</span>
                                        <input type="number" value={Math.round(item.style[key as keyof typeof item.style] as number || 0)} onChange={e => updateStyle(key as any, Number(e.target.value))} className="w-full bg-transparent text-xs font-mono outline-none text-right text-zinc-200" />
                                    </div>
                                ))}
                        </div>
                    </div>
                )}
            </div>
            <div className="p-4 border-t border-zinc-700 bg-[#222226] shrink-0"><button onClick={onDelete} className="w-full py-2 bg-red-900/20 text-red-500 hover:bg-red-900/40 border border-red-900/50 rounded-lg font-bold text-xs flex items-center justify-center gap-2"><i className="fa-solid fa-trash"></i> Bileşeni Sil</button></div>
        </div>
    );
}

