export const ReadingStudio: React.FC<any> = ({ onBack, onAddToWorkbook }) => {
    const { user } = useAuth();
    const [isLoading, setIsLoading] = useState(false);
    const [isSaving, setIsSaving] = useState(false);
    const [isSaved, setIsSaved] = useState(false);
    const [isShareModalOpen, setIsShareModalOpen] = useState(false);

    const [storyData, setStoryData] = useState<InteractiveStoryData | null>(null);
    const [sidebarTab, setSidebarTab] = useState<'settings' | 'library' | 'templates'>('settings');
    const [layout, setLayout] = useState<ActiveComponent[]>([]);
    const [selectedId, setSelectedId] = useState<string | null>(null);
    const [designMode, setDesignMode] = useState(true);

    const [config, setConfig] = useState<ReadingStudioConfig>({
        gradeLevel: '3. Sınıf', studentName: '', topic: '', genre: 'Macera', tone: 'Eğlenceli',
        length: 'medium', layoutDensity: 'comfortable', textComplexity: 'moderate',
        fontSettings: { family: 'OpenDyslexic', size: 16, lineHeight: 1.8, letterSpacing: 1, wordSpacing: 2 },
        includeImage: true, imageSize: 40, imageOpacity: 100, imagePosition: 'right',
        imageGeneration: { enabled: true, style: 'storybook', complexity: 'simple' },
        include5N1K: true, countMultipleChoice: 3, countTrueFalse: 2, countFillBlanks: 2, countLogic: 1, countInference: 1, 
        focusVocabulary: true, includeCreativeTask: true, includeWordHunt: false, includeSpellingCheck: false,
        showReadingTracker: false, showSelfAssessment: false, showTeacherNotes: false, showDateSection: true
    });

    const [templates, setTemplates] = useState<ReadingTemplate[]>([]);
    const [templateName, setTemplateName] = useState("");

    const [openSections, setOpenSections] = useState({ layers: true, add: false });
    const [isSidebarOpen, setIsSidebarOpen] = useState(true);

    const [canvasScale, setCanvasScale] = useState(0.85);
    const [canvasPos, setCanvasPos] = useState({ x: 0, y: 40 }); 
    const [isPanning, setIsPanning] = useState(false);
    const lastMousePos = useRef({ x: 0, y: 0 });
    const canvasRef = useRef<HTMLDivElement>(null);

    const [dragState, setDragState] = useState<{ mode: 'drag' | 'resize' | 'rotate'; resizeHandle?: string; startX: number; startY: number; initialX: number; initialY: number; initialW: number; initialH: number; initialR: number; centerX?: number; centerY?: number; } | null>(null);

    const contentHeight = useMemo(() => {
        if (layout.length === 0) return A4_HEIGHT_PX;
        const maxY = Math.max(...layout.map(item => item.style.y + item.style.h));
        return Math.max(A4_HEIGHT_PX, maxY + PAGE_BOTTOM_PADDING);
    }, [layout]);

    // LOAD TEMPLATES FROM CLOUD
    useEffect(() => {
        if (user) {
            loadCloudTemplates();
        }
    }, [user]);

    const loadCloudTemplates = async () => {
        if (!user) return;
        const data = await readingTemplateService.getTemplates(user.id);
        setTemplates(data);
    };

    useEffect(() => {
        if (canvasRef.current) {
            const viewportW = canvasRef.current.clientWidth;
            const pageWidth = A4_WIDTH_PX;
            const initialScale = Math.min(0.85, (viewportW - 100) / pageWidth); 
            const centeredX = (viewportW - (pageWidth * initialScale)) / 2;
            setCanvasScale(initialScale);
            setCanvasPos({ x: centeredX, y: 40 });
        }

        const generatedLayout: ActiveComponent[] = [];
        let currentY = 20;
        const startX = 20;
        const canvasWidth = A4_WIDTH_PX - (startX * 2);
        const gap = 15;

        COMPONENT_DEFINITIONS.forEach((def, index) => {
            let itemX = startX;
            let itemY = currentY;
            let itemW = canvasWidth;
            let itemH = def.defaultStyle.h || 100;
            if (def.id === 'tracker') { itemW = 200; itemX = A4_WIDTH_PX - 20 - 200; itemY = 35; } 
            else if (def.id === 'header') { currentY += itemH + gap; } 
            else { currentY += itemH + gap; }
            generatedLayout.push({ ...def, instanceId: `${def.id}-auto-${index}`, style: { ...DEFAULT_STYLE_BASE, ...def.defaultStyle, x: itemX, y: itemY, w: itemW, h: itemH, zIndex: def.id === 'tracker' ? 10 : index + 1 }, isVisible: true, customTitle: def.defaultTitle, themeColor: 'black', specificData: null });
        });
        setLayout(generatedLayout);
    }, []);

    useEffect(() => {
        if (!storyData) return;
        setLayout(prev => prev.map(item => {
            let specificData = item.specificData;
            if (item.id === 'header') specificData = { title: storyData.title || "HİKAYE", subtitle: `Tarih: .................... | ${storyData.genre}` };
            else if (item.id === 'story_block') specificData = { text: storyData.story, imagePrompt: storyData.imagePrompt };
            else if (item.id === 'questions_5n1k') specificData = { questions: (storyData.fiveW1H || []).map(q => ({ text: q.question })) };
            else if (item.id === 'questions_test') specificData = { questions: (storyData.multipleChoice || []).map(q => ({ text: q.question, options: q.options })) };
            else if (item.id === 'questions_inference') { const questions = [...(storyData.inferenceQuestions || []), ...(storyData.logicQuestions || [])].slice(0, 3); specificData = { questions: questions.map(q => ({ text: q.question })) }; }
            else if (item.id === 'vocabulary') specificData = { questions: (storyData.vocabulary || []).map(v => ({ text: `${v.word}: ${v.definition}` })) };
            else if (item.id === 'creative') specificData = { task: storyData.creativeTask || "Hikaye ile ilgili bir resim çiz." };
            return { ...item, specificData };
        }));
        setIsSaved(false);
    }, [storyData]);

    const handleCanvasWheel = useCallback((e: React.WheelEvent) => {
        if (e.ctrlKey) e.preventDefault();
        const zoomSensitivity = -0.001; 
        const delta = e.deltaY * zoomSensitivity;
        const newScale = Math.min(Math.max(0.2, canvasScale + delta), 4);
        if (canvasRef.current) {
            const rect = canvasRef.current.getBoundingClientRect();
            const mouseX = e.clientX - rect.left;
            const canvasX = (mouseX - canvasPos.x) / canvasScale;
            const newX = mouseX - canvasX * newScale;
            setCanvasScale(newScale);
            setCanvasPos(prev => ({ x: newX, y: prev.y }));
        }
    }, [canvasScale, canvasPos]);

    const handleBgMouseDown = (e: React.MouseEvent) => {
        if (!designMode) return;
        setIsPanning(true);
        lastMousePos.current = { x: e.clientX, y: e.clientY };
    };

    const handleMouseDown = (e: React.MouseEvent, id: string, mode: 'drag' | 'resize' | 'rotate' = 'drag', handle?: string) => {
        if (!designMode) return;
        e.stopPropagation();
        const item = layout.find(l => l.instanceId === id);
        if (!item) return;
        setSelectedId(id);
        let centerX = 0; let centerY = 0;
        if (mode === 'rotate') {
             const element = e.currentTarget.parentElement; 
             if (element) { const rect = element.getBoundingClientRect(); centerX = rect.left + rect.width / 2; centerY = rect.top + rect.height / 2; }
        }
        setDragState({ mode, resizeHandle: handle, startX: e.clientX, startY: e.clientY, initialX: item.style.x, initialY: item.style.y, initialW: item.style.w, initialH: item.style.h, initialR: item.style.rotation || 0, centerX, centerY });
    };

    useEffect(() => {
        const handleMouseMove = (e: MouseEvent) => {
            if (isPanning) { const dx = e.clientX - lastMousePos.current.x; setCanvasPos(prev => ({ x: prev.x + dx, y: prev.y })); lastMousePos.current = { x: e.clientX, y: e.clientY }; return; }
            if (!dragState || !selectedId) return;
            const dx = (e.clientX - dragState.startX) / canvasScale;
            const dy = (e.clientY - dragState.startY) / canvasScale;
            const snap = (val: number) => Math.round(val / SNAP_GRID) * SNAP_GRID;
            setLayout(prev => prev.map(item => {
                if (item.instanceId !== selectedId) return item;
                let newStyle = { ...item.style };
                if (dragState.mode === 'drag') { newStyle.x = snap(dragState.initialX + dx); newStyle.y = snap(dragState.initialY + dy); } 
                else if (dragState.mode === 'resize' && dragState.resizeHandle) {
                    const h = dragState.resizeHandle;
                    if (h.includes('e')) newStyle.w = Math.max(50, snap(dragState.initialW + dx));
                    if (h.includes('w')) { const newW = Math.max(50, snap(dragState.initialW - dx)); newStyle.x = snap(dragState.initialX + (dragState.initialW - newW)); newStyle.w = newW; }
                    if (h.includes('s')) newStyle.h = Math.max(50, snap(dragState.initialH + dy));
                    if (h.includes('n')) { const newH = Math.max(50, snap(dragState.initialH - dy)); newStyle.y = snap(dragState.initialY + (dragState.initialH - newH)); newStyle.h = newH; }
                } else if (dragState.mode === 'rotate' && dragState.centerX && dragState.centerY) {
                    const currentAngle = Math.atan2(e.clientY - dragState.centerY, e.clientX - dragState.centerX);
                    const startAngle = Math.atan2(dragState.startY - dragState.centerY, dragState.startX - dragState.centerX);
                    const deg = (currentAngle - startAngle) * (180 / Math.PI);
                    let finalR = Math.round(dragState.initialR + deg);
                    if (e.shiftKey) finalR = Math.round(finalR / 45) * 45;
                    newStyle.rotation = finalR;
                }
                return { ...item, style: newStyle };
            }));
        };
        const handleMouseUp = () => { setDragState(null); setIsPanning(false); };
        if (dragState || isPanning) { window.addEventListener('mousemove', handleMouseMove); window.addEventListener('mouseup', handleMouseUp); }
        return () => { window.removeEventListener('mousemove', handleMouseMove); window.removeEventListener('mouseup', handleMouseUp); };
    }, [dragState, selectedId, isPanning, canvasScale]);

    const addComponent = (def: ComponentDefinition) => {
        const newId = `${def.id}-${Date.now()}`;
        const newItem: ActiveComponent = { ...def, instanceId: newId, style: { ...DEFAULT_STYLE_BASE, ...def.defaultStyle, x: 20, y: 20 }, isVisible: true, customTitle: def.defaultTitle, themeColor: 'black', specificData: null };
        setLayout(prev => [...prev, newItem]);
        setSelectedId(newId);
    };

    const updateItem = (updates: Partial<ActiveComponent>) => { if (!selectedId) return; setLayout(prev => prev.map(item => item.instanceId === selectedId ? { ...item, ...updates } : item)); setIsSaved(false); };
    const deleteItem = () => { if (!selectedId) return; removeComponent(selectedId); };

    const removeComponent = (id: string) => {
        if(confirm("Bu bileşeni silmek istediğinize emin misiniz?")) {
            const itemToRemove = layout.find(item => item.instanceId === id);
            if (!itemToRemove) return;
            const gap = 15; const removedHeight = itemToRemove.style.h + gap; const removedY = itemToRemove.style.y;
            setLayout(prev => { const filtered = prev.filter(item => item.instanceId !== id); return filtered.map(item => { if (item.style.y > removedY) { return { ...item, style: { ...item.style, y: item.style.y - removedHeight } }; } return item; }); });
            if(selectedId === id) setSelectedId(null);
            setIsSaved(false);
        }
    };

    const saveTemplate = async () => {
        if(!user) { alert("Lütfen giriş yapın."); return; }
        if(!templateName.trim()) return alert("Lütfen şablon adı giriniz.");
        setIsSaving(true);
        try {
            await readingTemplateService.saveTemplate(user.id, templateName, layout);
            setTemplateName("");
            loadCloudTemplates();
            alert("Şablon buluta kaydedildi.");
        } catch (e) { alert("Hata oluştu."); } finally { setIsSaving(false); }
    };

    const loadTemplate = (t: ReadingTemplate) => {
        if(confirm("Mevcut düzen silinecek ve şablon yüklenecek. Onaylıyor musunuz?")) {
            const newLayout = t.layout.map((item) => ({ ...item, instanceId: item.id + '-' + Date.now() + Math.random().toString(36).substr(2, 5) }));
            setLayout(newLayout);
            setIsSaved(false);
        }
    };

    const deleteTemplate = async (id: string) => {
         if(!user) return;
         if(confirm("Şablonu silmek istediğinize emin misiniz?")) {
            await readingTemplateService.deleteTemplate(user.id, id);
            loadCloudTemplates();
         }
    };

    const handleGenerate = async () => {
        setIsLoading(true);
        try { const data = await generateInteractiveStory(config); setStoryData(data); } 
        catch (e) { alert("Hata oluştu."); } finally { setIsLoading(false); }
    };

    const handlePrint = async (action: 'print' | 'download') => {
        const prevMode = designMode; const prevSelected = selectedId;
        setDesignMode(false); setSelectedId(null);
        setTimeout(async () => { await printService.generatePdf('#canvas-root', storyData?.title || 'Hikaye', { action }); setDesignMode(prevMode); setSelectedId(prevSelected); }, 300);
    };

    const handleSaveToArchive = async () => {
        if (!user) { alert("Giriş yapın."); return; }
        if (!storyData && layout.length === 0) return;
        setIsSaving(true);
        try {
            const title = storyData?.title || (layout.find(l => l.id === 'header')?.specificData as any)?.title || 'Yeni Hikaye';
            await worksheetService.saveWorksheet(user.id, title, 'STORY_COMPREHENSION', [{ storyData, layout }], 'fa-solid fa-book-open-reader', { id: 'reading-verbal', title: 'Okuma & Dil' });
            setIsSaved(true);
            alert("Arşivlendi.");
        } catch (e) { alert("Hata!"); } finally { setIsSaving(false); }
    };

    const handleAddToWorkbook = () => {
        if (!storyData && layout.length === 0) return;
        if (onAddToWorkbook) { onAddToWorkbook({ storyData, layout }); }
    };

    const handleShare = async (receiverId: string) => {
        if (!user) return;
        try {
            const title = storyData?.title || 'Paylaşılan Hikaye';
            await worksheetService.shareWorksheet({ name: title, activityType: 'STORY_COMPREHENSION', worksheetData: [{ storyData, layout }], icon: 'fa-solid fa-share-nodes', category: { id: 'reading-verbal', title: 'Okuma & Dil' } } as any, user.id, user.name, receiverId);
            setIsShareModalOpen(false); alert("Paylaşıldı.");
        } catch (e) { alert("Hata."); }
    };

    const toggleSection = (section: 'layers' | 'add') => { setOpenSections(prev => ({ ...prev, [section]: !prev[section] })); };

    const renderContent = (item: ActiveComponent) => {
        const s = item.style;
        const boxStyle = { padding: `${s.padding}px`, backgroundColor: s.backgroundColor, borderColor: s.borderColor, borderWidth: `${s.borderWidth}px`, borderStyle: s.borderStyle || 'solid', borderRadius: `${s.borderRadius}px`, boxShadow: s.boxShadow !== 'none' ? `var(--shadow-${s.boxShadow})` : 'none', opacity: s.opacity, color: s.color, fontFamily: s.fontFamily, fontSize: `${s.fontSize}px`, lineHeight: s.lineHeight, textAlign: s.textAlign as any, letterSpacing: `${s.letterSpacing}px`, fontWeight: s.fontWeight || 'normal' };
        if (item.id === 'header') {
            const data = item.specificData || { title: "HİKAYE BAŞLIĞI", subtitle: `Tarih: ....................` };
            return ( <div className="h-full flex flex-col justify-end" style={boxStyle}><h1 className="font-black uppercase leading-none tracking-tight" style={{fontSize: '2.5em', color: 'inherit'}}>{data.title}</h1><div className="flex justify-between items-end mt-2 opacity-70"><span className="font-mono text-sm">{data.subtitle}</span></div></div> );
        }
        if (item.id === 'tracker') { return ( <div className="h-full flex flex-col items-center justify-center" style={boxStyle}><div className="flex gap-4">{[1, 2, 3].map(i => ( <div key={i} className="w-10 h-10 rounded-full border-2 border-current bg-transparent flex items-center justify-center"><i className="fa-regular fa-star text-sm opacity-50"></i></div> ))}</div></div> ); }
        if (item.id === 'story_block') {
            const data = item.specificData || { text: "Bekleniyor...", imagePrompt: "" };
            return ( <div className="h-full relative overflow-hidden" style={boxStyle}>{item.style.imageSettings?.enabled && ( <div className={`float-${item.style.imageSettings.position === 'left' ? 'left' : 'right'} w-1/3 h-48 bg-transparent ml-4 mb-2 rounded-lg relative z-10`}><ImageDisplay prompt={data.imagePrompt} description="Görsel" className="w-full h-full object-contain" /></div> )}<div dangerouslySetInnerHTML={{__html: (data.text || '').replace(/\n/g, '<br/>')}}></div></div> );
