        }
        if (item.id === 'notes') { return ( <div className="h-full flex flex-col" style={boxStyle}><h4 className="font-black text-xs uppercase mb-2 border-b pb-1 opacity-50">{item.customTitle}</h4><div className="flex-1" style={{backgroundImage: 'linear-gradient(transparent 95%, currentColor 95%)', backgroundSize: '100% 1.5rem', opacity: 0.3}}></div></div> ); }
        if (item.id.startsWith('questions')) {
            const data = item.specificData || { questions: [{text: "Soru..."}] };
            return ( <div className="h-full flex flex-col" style={boxStyle}><h4 className="font-black text-xs uppercase mb-2 border-b pb-1 opacity-50">{item.customTitle}</h4><div className="flex-1 space-y-2 overflow-hidden">{(data.questions || []).map((q: any, i: number) => ( <div key={i} className="flex gap-2 items-start"><span className="font-bold bg-current text-white w-5 h-5 rounded-full flex items-center justify-center text-[10px] shrink-0" style={{color: s.backgroundColor === 'transparent' ? 'white' : s.backgroundColor, backgroundColor: s.color}}>{i+1}</span><p className="leading-snug pt-0.5">{q.text}</p></div> ))}</div></div> );
        }
        return ( <div className="h-full flex items-center justify-center border-2 border-dashed border-zinc-300 rounded" style={boxStyle}><span className="opacity-50 font-bold">{item.label}</span></div> );
    };

    return (
        <div className="h-full flex flex-col bg-[#222226] font-['OpenDyslexic'] overflow-hidden text-zinc-100">
            <div className="h-14 bg-[#2d2d32] border-b border-zinc-800 flex justify-between items-center px-4 shrink-0 z-50">
                <div className="flex items-center gap-3"><button onClick={onBack} className="w-8 h-8 rounded hover:bg-zinc-700 flex items-center justify-center text-zinc-400"><i className="fa-solid fa-arrow-left"></i></button><span className="font-black text-sm uppercase tracking-widest text-amber-500">Reading Studio <span className="bg-amber-500/20 text-amber-500 px-1 rounded text-[9px] border border-amber-500/50">PRO</span></span></div>
                <div className="flex items-center gap-2">
                     <button onClick={() => setDesignMode(!designMode)} className={`px-3 py-1.5 rounded text-xs font-bold border transition-colors ${designMode ? 'bg-amber-500 text-black border-amber-500' : 'bg-zinc-800 border-zinc-700 text-zinc-300 hover:bg-zinc-700'}`}>{designMode ? 'MİMARİ MOD' : 'ÖNİZLEME'}</button>
                     <div className="h-8 w-px bg-zinc-700 mx-2"></div>
