                     <button onClick={() => handlePrint('print')} className="w-8 h-8 rounded hover:bg-zinc-700 flex items-center justify-center text-zinc-400" title="Yazdır"><i className="fa-solid fa-print"></i></button>
                     <button id="rs-workbook-btn" onClick={handleAddToWorkbook} className="px-4 py-1.5 rounded-lg text-xs font-bold bg-emerald-600 hover:bg-emerald-700 text-white shadow-lg border border-emerald-500">Kitapçığa Ekle</button>
                     <button onClick={handleSaveToArchive} disabled={isSaving || isSaved} className={`px-4 py-1.5 rounded-lg text-xs font-bold transition-all flex items-center gap-2 ${isSaved ? 'bg-green-600 text-white' : 'bg-indigo-600 text-white hover:bg-indigo-700 shadow-lg'}`}>{isSaving ? <i className="fa-solid fa-circle-notch fa-spin"></i> : (isSaved ? <i className="fa-solid fa-check"></i> : <i className="fa-solid fa-save"></i>)}{isSaved ? 'Arşivlendi' : 'Arşive Kaydet'}</button>
                </div>
            </div>
            <div className="flex-1 flex overflow-hidden relative">
                <div className={`flex-shrink-0 h-full bg-[#18181b] border-r border-zinc-800 transition-all duration-300 ease-in-out overflow-hidden z-40 ${isSidebarOpen ? 'w-80 opacity-100' : 'w-0 opacity-0 border-r-0'}`}>
                    <div className="w-80 flex flex-col h-full"> 
                         <div className="flex border-b border-zinc-800 bg-[#222226]"><button onClick={() => setSidebarTab('settings')} className={`flex-1 py-3 text-xs font-bold uppercase transition-colors ${sidebarTab === 'settings' ? 'text-amber-500 border-b-2 border-amber-500' : 'text-zinc-500 hover:text-zinc-300'}`}>Ayarlar</button><button onClick={() => setSidebarTab('library')} className={`flex-1 py-3 text-xs font-bold uppercase transition-colors ${sidebarTab === 'library' ? 'text-amber-500 border-b-2 border-amber-500' : 'text-zinc-500 hover:text-zinc-300'}`}>Bileşenler</button><button onClick={() => setSidebarTab('templates')} className={`flex-1 py-3 text-xs font-bold uppercase transition-colors ${sidebarTab === 'templates' ? 'text-amber-500 border-b-2 border-amber-500' : 'text-zinc-500 hover:text-zinc-300'}`}>Şablonlar</button></div>
                         <div className="flex-1 flex flex-col min-h-0 overflow-y-auto custom-scrollbar">
                             {sidebarTab === 'library' && ( <div className="flex flex-col"><div className="border-b border-zinc-800"><button onClick={() => toggleSection('layers')} className="w-full flex items-center justify-between p-4 bg-[#18181b] hover:bg-zinc-800 transition-colors"><h4 className="text-[10px] font-black text-zinc-400 uppercase tracking-widest flex items-center gap-2"><i className="fa-solid fa-layer-group"></i> KATMANLAR <span className="bg-zinc-800 px-1.5 py-0.5 rounded text-zinc-500">{layout.length}</span></h4><i className={`fa-solid fa-chevron-down text-xs text-zinc-500 transition-transform ${openSections.layers ? 'rotate-180' : ''}`}></i></button>{openSections.layers && ( <div className="p-2 space-y-1 bg-[#222226] animate-in slide-in-from-top-2 duration-200">{layout.map((item) => ( <div key={item.instanceId} onClick={() => setSelectedId(item.instanceId)} className={`group flex items-center gap-3 p-2 rounded-lg border transition-all cursor-pointer ${selectedId === item.instanceId ? 'border-amber-500/50 bg-amber-500/10 shadow-sm ring-1 ring-amber-500/30' : 'border-transparent hover:bg-zinc-800 border-zinc-800'}`}><div className={`w-7 h-7 rounded flex items-center justify-center text-xs ${selectedId === item.instanceId ? 'bg-amber-500 text-black' : 'bg-zinc-800 text-zinc-500'}`}><i className={`fa-solid ${item.icon}`}></i></div><div className="flex-1 min-w-0"><p className={`text-xs font-bold truncate ${selectedId === item.instanceId ? 'text-amber-500' : 'text-zinc-300'}`}>{item.customTitle || item.label}</p></div><div className="flex items-center gap-1 opacity-0 group-hover:opacity-100"><button onClick={(e) => { e.stopPropagation(); removeComponent(item.instanceId); }} className="w-6 h-6 flex items-center justify-center rounded hover:bg-red-900/30 text-zinc-400 hover:text-red-500"><i className="fa-solid fa-trash"></i></button></div></div> ))}</div> )}</div><div><button onClick={() => toggleSection('add')} className="w-full flex items-center justify-between p-4 bg-[#18181b] hover:bg-zinc-800 transition-colors border-b border-zinc-800"><h4 className="text-[10px] font-black text-zinc-400 uppercase tracking-widest flex items-center gap-2"><i className="fa-solid fa-plus-circle"></i> YENİ EKLE</h4><i className={`fa-solid fa-chevron-down text-xs text-zinc-500 transition-transform ${openSections.add ? 'rotate-180' : ''}`}></i></button>{openSections.add && ( <div className="p-4 bg-[#222226] animate-in slide-in-from-top-2 duration-200"><div className="grid grid-cols-2 gap-2">{COMPONENT_DEFINITIONS.map(def => ( <button key={def.id} onClick={() => addComponent(def)} className="flex flex-col items-center gap-2 p-3 bg-zinc-800 border border-zinc-700 rounded-xl hover:border-amber-500 transition-all group"><i className={`fa-solid ${def.icon} text-zinc-500 group-hover:text-amber-500 text-lg`}></i><span className="text-[10px] font-bold text-zinc-400 group-hover:text-amber-500 text-center">{def.label}</span></button> ))}</div></div> )}</div></div> )}
                             {sidebarTab === 'templates' && ( <div className="p-4 space-y-6"><div className="bg-zinc-800/50 p-4 rounded-xl border border-zinc-800"><h4 className="text-[10px] font-bold text-zinc-400 uppercase mb-2">Şablon Kaydet</h4><div className="flex gap-2"><input type="text" value={templateName} onChange={e => setTemplateName(e.target.value)} placeholder="Şablon Adı..." className="flex-1 p-2 bg-zinc-900 border border-zinc-700 rounded text-xs text-white outline-none" /><button onClick={saveTemplate} disabled={isSaving} className="px-3 bg-amber-500 text-black rounded font-bold text-xs hover:bg-amber-400">{isSaving ? '...' : <i className="fa-solid fa-save"></i>}</button></div></div><div><h4 className="text-[10px] font-bold text-zinc-500 uppercase mb-3">Kayıtlı Şablonlar</h4>{templates.length === 0 ? ( <div className="text-center text-zinc-600 text-xs py-4">Henüz şablon yok.</div> ) : ( <div className="space-y-3">{templates.map(t => ( <div key={t.id} className="group bg-zinc-800 border border-zinc-700 rounded-lg p-3 hover:border-amber-500/50 cursor-pointer" onClick={() => loadTemplate(t)}><div className="flex justify-between items-start mb-2"><h5 className="font-bold text-sm text-zinc-200">{t.name}</h5><button onClick={(e) => {e.stopPropagation(); deleteTemplate(t.id);}} className="text-zinc-500 hover:text-red-500"><i className="fa-solid fa-trash"></i></button></div><div className="w-full h-12 bg-white/5 rounded relative overflow-hidden pointer-events-none opacity-40"><div className="absolute inset-0" style={{transform: 'scale(0.1)', transformOrigin: '0 0', width: '1000%', height: '1000%'}}>{t.layout.map((item: any, idx: number) => ( <div key={idx} style={{ position: 'absolute', left: item.style.x, top: item.style.y, width: item.style.w, height: item.style.h, border: '4px solid white' }}></div> ))}</div></div></div> ))}</div> )}</div></div> )}
                             {sidebarTab === 'settings' && ( <div className="p-4 space-y-6"><div className="space-y-3"><h4 className="text-[10px] font-black text-zinc-400 uppercase tracking-widest flex items-center gap-2"><i className="fa-solid fa-user-graduate"></i> Öğrenci</h4><div><input type="text" value={config.studentName} onChange={e => setConfig({...config, studentName: e.target.value})} className="w-full p-2 border border-zinc-700 rounded bg-zinc-900 text-xs" placeholder="Ad Soyad" /></div></div><div className="space-y-3"><h4 className="text-[10px] font-black text-zinc-400 uppercase tracking-widest flex items-center gap-2"><i className="fa-solid fa-book"></i> Hikaye Kurgusu</h4><div><input type="text" value={config.topic} onChange={e => setConfig({...config, topic: e.target.value})} className="w-full p-2 border border-zinc-700 rounded bg-zinc-900 text-xs" placeholder="Konu" /></div><div className="grid grid-cols-2 gap-2"><div><select value={config.genre} onChange={e => setConfig({...config, genre: e.target.value})} className="w-full p-2 border border-zinc-700 rounded bg-zinc-900 text-xs">{['Macera', 'Masal', 'Fabl'].map(g => <option key={g} value={g}>{g}</option>)}</select></div><div><select value={config.tone} onChange={e => setConfig({...config, tone: e.target.value})} className="w-full p-2 border border-zinc-700 rounded bg-zinc-900 text-xs">{['Eğlenceli', 'Öğretici'].map(t => <option key={t} value={t}>{t}</option>)}</select></div></div></div><button onClick={handleGenerate} disabled={isLoading} className="w-full py-4 bg-amber-500 hover:bg-amber-400 text-black rounded-xl font-bold text-sm shadow-lg flex items-center justify-center gap-2">{isLoading ? <i className="fa-solid fa-circle-notch fa-spin"></i> : <i className="fa-solid fa-wand-magic-sparkles"></i>}{isLoading ? 'Yazılıyor...' : 'Hikaye Oluştur'}</button></div> )}
                         </div>
                    </div>
                </div>
                <button onClick={() => setIsSidebarOpen(!isSidebarOpen)} className={`absolute top-1/2 -translate-y-1/2 z-50 w-5 h-12 bg-[#2d2d32] border rounded-r-lg flex items-center justify-center text-zinc-400 hover:bg-amber-500 transition-all`} style={{ left: isSidebarOpen ? '320px' : '0px' }}><i className={`fa-solid fa-chevron-${isSidebarOpen ? 'left' : 'right'} text-xs`}></i></button>
                <div ref={canvasRef} className="flex-1 bg-[#121214] overflow-hidden flex items-center justify-center relative cursor-grab active:cursor-grabbing" onWheel={handleCanvasWheel} onMouseDown={handleBgMouseDown}>
                    <div className="origin-top transition-transform duration-75 ease-out" style={{ transform: `translate3d(${canvasPos.x}px, ${canvasPos.y}px, 0) scale(${canvasScale})` }}>
                        <div id="canvas-root" className="bg-white shadow-2xl relative" style={{ width: `${A4_WIDTH_PX}px`, height: `${contentHeight}px`, transformOrigin: '0 0' }}>
                            {designMode && <div className="absolute inset-0 pointer-events-none" style={{backgroundImage: `radial-gradient(#e5e7eb 1px, transparent 1px)`, backgroundSize: `${SNAP_GRID * 4}px ${SNAP_GRID * 4}px`}}></div>}
                            {layout.filter(l => l.isVisible).map((item) => (
                                <div key={item.instanceId} onMouseDown={(e) => handleMouseDown(e, item.instanceId, 'drag')} className={`absolute ${designMode ? 'hover:ring-1 hover:ring-amber-500 cursor-move' : ''}`} style={{ left: item.style.x, top: item.style.y, width: item.style.w, height: item.style.h, transform: `rotate(${item.style.rotation || 0}deg)`, zIndex: item.style.zIndex }}>
                                    {designMode && selectedId === item.instanceId && ( <div className="absolute inset-0 border-2 border-amber-500 z-50 pointer-events-none"><div className="pointer-events-auto"><RotateHandle onMouseDown={(e) => handleMouseDown(e, item.instanceId, 'rotate')} /></div><div className="pointer-events-auto"><ResizeHandle cursor="se-resize" position="-bottom-1.5 -right-1.5" onMouseDown={(e) => handleMouseDown(e, item.instanceId, 'resize', 'se')} /></div></div> )}
                                    <div className="w-full h-full overflow-hidden pointer-events-none text-black">{renderContent(item)}</div>
                                </div>
                            ))}
                            <div className="absolute bottom-4 left-0 w-full px-8 flex justify-between text-[10px] text-zinc-400 font-mono"><span>Bursa Disleksi AI © {new Date().getFullYear()}</span><span>Sayfa 1</span></div>
                        </div>
                    </div>
                </div>
                {selectedId && ( <div className="shrink-0 z-50 h-full border-l border-zinc-800 shadow-xl relative"><SettingsStation item={layout.find(l => l.instanceId === selectedId)!} onUpdate={updateItem} onClose={() => setSelectedId(null)} onDelete={deleteItem} /></div> )}
            </div>
            <ShareModal isOpen={isShareModalOpen} onClose={() => setIsShareModalOpen(false)} onShare={handleShare} worksheetTitle={storyData?.title || 'Hikaye'} />
        </div>
    );
};

import React, { useState, useEffect, useCallback, Suspense, lazy } from 'react';
import { ActivityType, WorksheetData, SavedWorksheet, SingleWorksheetData, AppTheme, HistoryItem, StyleSettings, View, UiSettings, CollectionItem, WorkbookSettings, StudentProfile, AssessmentReport, GeneratorOptions, SavedAssessment } from './types';
import Sidebar from './components/Sidebar';
import ContentArea from './components/ContentArea';
import { ACTIVITIES, ACTIVITY_CATEGORIES } from './constants';
import DyslexiaLogo from './components/DyslexiaLogo';
import GlobalSearch from './components/GlobalSearch';
import { FeedbackModal } from './components/FeedbackModal';
import { AuthProvider, useAuth } from './context/AuthContext';
import { AuthModal } from './components/AuthModal';
import { historyService } from './services/historyService';
import { worksheetService } from './services/worksheetService';
import { SettingsModal } from './components/SettingsModal';
import { TourGuide, TourStep } from './components/TourGuide';
import { StudentInfoModal } from './components/StudentInfoModal';

// Lazy Loaded Components
const ProfileView = lazy(() => import('./components/ProfileView').then(module => ({ default: module.ProfileView })));
const AdminDashboard = lazy(() => import('./components/AdminDashboard').then(module => ({ default: module.AdminDashboard })));
const MessagesView = lazy(() => import('./components/MessagesView').then(module => ({ default: module.MessagesView })));
const OCRScanner = lazy(() => import('./components/OCRScanner').then(module => ({ default: module.OCRScanner })));
const CurriculumView = lazy(() => import('./components/CurriculumView').then(module => ({ default: module.CurriculumView })));
const ReadingStudio = lazy(() => import('./components/ReadingStudio/ReadingStudio').then(module => ({ default: module.ReadingStudio })));

const initialStyleSettings: StyleSettings = { fontSize: 16, scale: 1, borderColor: '#d4d4d8', borderWidth: 1, margin: 20, columns: 1, gap: 16, orientation: 'portrait', themeBorder: 'simple', contentAlign: 'center', fontWeight: 'normal', fontStyle: 'normal', visualStyle: 'card', showPedagogicalNote: false, showMascot: false, showStudentInfo: false, showTitle: false, showInstruction: false, showImage: false, showFooter: false, smartPagination: false, fontFamily: 'OpenDyslexic', lineHeight: 1.5, letterSpacing: 0 };
const initialUiSettings: UiSettings = { fontFamily: 'OpenDyslexic', fontSizeScale: 1, letterSpacing: 'normal', lineHeight: 1.6, saturation: 100 };

const LoadingSpinner = () => ( <div className="flex items-center justify-center h-full w-full min-h-[200px]"><div className="w-10 h-10 border-4 border-indigo-200 border-t-indigo-600 rounded-full animate-spin"></div></div> );

const AppContent: React.FC = () => {
    const { user, logout } = useAuth();
    const [currentView, setCurrentView] = useState<View | 'ocr' | 'curriculum' | 'reading-studio'>('generator');
    const [viewHistory, setViewHistory] = useState<(View | 'ocr' | 'curriculum' | 'reading-studio')[]>([]); 

    const [selectedActivity, setSelectedActivity] = useState<ActivityType | null>(null);
    const [worksheetData, setWorksheetData] = useState<WorksheetData>(null);
    const [isLoading, setIsLoading] = useState<boolean>(false);
    const [error, setError] = useState<string | null>(null);
    const [isSidebarOpen, setIsSidebarOpen] = useState(false);
    const [isSidebarExpanded, setIsSidebarExpanded] = useState(true);
    const [openModal, setOpenModal] = useState<'settings' | 'history' | 'about' | 'developer' | null>(null);
    const [isFeedbackOpen, setIsFeedbackOpen] = useState(false);
    const [isAuthModalOpen, setIsAuthModalOpen] = useState(false);
    const [isTourOpen, setIsTourOpen] = useState(false);
    const [studentProfile, setStudentProfile] = useState<StudentProfile | null>(null);
    const [isStudentModalOpen, setIsStudentModalOpen] = useState(false);
    const [workbookItems, setWorkbookItems] = useState<CollectionItem[]>([]);
    const [workbookSettings, setWorkbookSettings] = useState<WorkbookSettings>({ title: 'Çalışma Kitapçığı', studentName: '', schoolName: '', year: new Date().getFullYear().toString(), teacherNote: '', theme: 'modern', accentColor: '#4f46e5', coverStyle: 'centered', showTOC: true, showPageNumbers: true, showWatermark: false, watermarkOpacity: 0.05, showBackCover: true });
    const [theme, setTheme] = useState<AppTheme>('anthracite');
    const [uiSettings, setUiSettings] = useState<UiSettings>(initialUiSettings);
    const [styleSettings, setStyleSettings] = useState<StyleSettings>(initialStyleSettings);
    const [historyItems, setHistoryItems] = useState<HistoryItem[]>([]);

    // SYNC HISTORY ON LOGIN
    useEffect(() => {
        if (user) {
            historyService.getHistory(user.id).then(setHistoryItems);
        } else {
            setHistoryItems([]);
        }
    }, [user]);

    const navigateTo = (view: View | 'ocr' | 'curriculum' | 'reading-studio') => {
        if (currentView === view) return;
        setViewHistory(prev => [...prev, currentView]);
        setCurrentView(view);
    };

    const handleGoBack = () => {
        if (viewHistory.length > 0) {
            const newHistory = [...viewHistory];
            const prevView = newHistory.pop();
            setViewHistory(newHistory);
            if (prevView) setCurrentView(prevView);
        } else { setCurrentView('generator'); }
    };

    const addToHistory = async (activityType: ActivityType, data: SingleWorksheetData[]) => {
        const activity = ACTIVITIES.find(a => a.id === activityType);
        const category = ACTIVITY_CATEGORIES.find(c => c.activities.includes(activityType));
        if (!activity || !category) return;

        const newItem = {
            userId: user?.id || 'guest',
            activityType,
            data,
            timestamp: new Date().toISOString(),
            title: activity.title,
            category: { id: category.id, title: category.title }
        };

        if (user) {
            await historyService.addToHistory(user.id, newItem);
            const updatedHistory = await historyService.getHistory(user.id);
            setHistoryItems(updatedHistory);
        } else {
            setHistoryItems(prev => [ { ...newItem, id: Date.now().toString() }, ...prev ].slice(0, 20));
        }
    };

    const clearHistory = async () => { if (user) { await historyService.clearHistory(user.id); setHistoryItems([]); } };
    const deleteHistoryItem = async (id: string) => { if (user) { await historyService.deleteHistoryItem(user.id, id); setHistoryItems(prev => prev.filter(i => i.id !== id)); } };

    const handleRestoreFromHistory = (item: HistoryItem) => {
        setSelectedActivity(item.activityType);
        setWorksheetData(item.data);
        navigateTo('generator');
        setOpenModal(null);
    };

    const handleSaveHistoryItem = async (item: HistoryItem) => {
        if (!user) { setIsAuthModalOpen(true); return; }
        await worksheetService.saveWorksheet(user.id, `${item.title} (Geçmiş)`, item.activityType, item.data, 'fa-solid fa-clock-rotate-left', item.category);
        alert("Arşive kaydedildi.");
    };

    const loadSavedWorksheet = (worksheet: SavedWorksheet) => {
        if (worksheet.activityType === ActivityType.WORKBOOK) {
            if (worksheet.workbookItems && worksheet.workbookSettings) {
                setWorkbookItems(worksheet.workbookItems);
                setWorkbookSettings(worksheet.workbookSettings);
                navigateTo('workbook');
            }
        } else {
            setSelectedActivity(worksheet.activityType);
            setWorksheetData(worksheet.worksheetData);
            if (worksheet.styleSettings) setStyleSettings(worksheet.styleSettings);
            if (worksheet.studentProfile) setStudentProfile(worksheet.studentProfile);
            navigateTo('generator');
        }
    };

    return (
        <div className="flex flex-col h-screen bg-transparent font-sans transition-colors duration-300">
            <header className="relative bg-[var(--panel-bg)] backdrop-blur-sm border-b border-[var(--border-color)] shadow-sm z-10">
                <div className="w-full px-4 sm:px-6 py-3 flex justify-between items-center">
                    <button id="tour-logo" onClick={() => { navigateTo('generator'); setSelectedActivity(null); }} className="flex items-center gap-3 px-2 py-1 rounded-lg"><DyslexiaLogo className="h-10 w-auto" /></button>
                    <div className="flex items-center gap-2">
                        <GlobalSearch onSelectActivity={(id) => { setSelectedActivity(id); navigateTo('generator'); }} />
