const addComponent = (def: ComponentDefinition) => {
    const newId = `${def.id}-${Date.now()}`;

    // --- SMART PLACEMENT LOGIC ---
    // Find the bottom-most edge of existing components to place the new one below
    let nextY = 20;
    const gap = 15;

    if (layout.length > 0) {
        // Calculate max(y + height) of all current items
        const maxY = Math.max(...layout.map(item => item.style.y + item.style.h));
        nextY = maxY + gap;
    }

    const newItem: ActiveComponent = { 
        ...def, 
        instanceId: newId, 
        style: { 
            ...DEFAULT_STYLE_BASE, 
            ...def.defaultStyle, 
            x: 20, 
            y: nextY 
        }, 
        isVisible: true, 
        customTitle: def.defaultTitle, 
        themeColor: 'black', 
        specificData: null 
    };
    setLayout(prev => [...prev, newItem]);
    setSelectedId(newId);
};

import React, { useState, useRef, useEffect } from 'react';
import { useAuth } from '../../context/AuthContext';
import { printService } from '../../utils/printService';
import { worksheetService } from '../../services/worksheetService';
import { generateInteractiveStory } from '../../services/generators/readingStudio';
import { ReadingStudioConfig, InteractiveStoryData, LayoutItemStyle } from '../../types';
import { EditableText, EditableElement } from '../Editable';
import { ImageDisplay } from '../sheets/common';

interface ReadingStudioProps {
    onBack: () => void;
    onAddToWorkbook?: (data: any) => void;
}

interface ComponentDefinition {
    id: string;
    label: string;
    icon: string;
    defaultTitle: string;
    defaultStyle: Partial<LayoutItemStyle>;
}

interface ActiveComponent extends ComponentDefinition {
    instanceId: string;
    style: LayoutItemStyle;
    isVisible: boolean;
    customTitle?: string;
    themeColor?: string;
    specificData?: any;
}

const DEFAULT_STYLE_BASE: LayoutItemStyle = {
    x: 0,
    y: 0,
    w: 700,
    h: 100,
    rotation: 0,
    zIndex: 1,
    padding: 20,
    backgroundColor: 'transparent',
    borderColor: 'transparent',
    borderWidth: 0
};

const AVAILABLE_COMPONENTS: ComponentDefinition[] = [
    { id: 'header', label: 'Başlık & Künye', icon: 'fa-heading', defaultTitle: '', defaultStyle: { h: 120 } },
    { id: 'story_block', label: 'Hikaye Metni', icon: 'fa-book-open', defaultTitle: 'Okuma Parçası', defaultStyle: { h: 400 } },
    { id: 'vocabulary', label: 'Sözlükçe', icon: 'fa-spell-check', defaultTitle: 'Yeni Kelimeler', defaultStyle: { h: 200 } },
    { id: 'questions_5n1k', label: '5N 1K', icon: 'fa-magnifying-glass', defaultTitle: '5N 1K Soruları', defaultStyle: { h: 300 } },
    { id: 'questions_test', label: 'Test Soruları', icon: 'fa-list-ol', defaultTitle: 'Değerlendirme', defaultStyle: { h: 300 } },
    { id: 'creative', label: 'Yaratıcı Görev', icon: 'fa-paintbrush', defaultTitle: 'Senin Sıran', defaultStyle: { h: 200 } },
];

export const ReadingStudio: React.FC<ReadingStudioProps> = ({ onBack, onAddToWorkbook }) => {
    const { user } = useAuth();
    const [config, setConfig] = useState<ReadingStudioConfig>({
        gradeLevel: '2. Sınıf',
        studentName: '',
        topic: 'Uzay Macerası',
        genre: 'Macera',
        tone: 'Eğlenceli',
        length: 'medium',
        textComplexity: 'moderate',
        fontSettings: { family: 'OpenDyslexic', size: 16, lineHeight: 1.8, letterSpacing: 1, wordSpacing: 2 },
        layoutDensity: 'comfortable',
        imageGeneration: { enabled: true, style: 'cartoon', complexity: 'simple' },
        includeImage: true, imageSize: 50, imagePosition: 'right', imageOpacity: 100,
        include5N1K: true, countMultipleChoice: 3, countTrueFalse: 2, countFillBlanks: 2, countLogic: 1, countInference: 1,
        includeWordHunt: true, includeSpellingCheck: false, focusVocabulary: true, includeCreativeTask: true,
        showReadingTracker: true, showSelfAssessment: true, showTeacherNotes: false, showDateSection: true
    });

    const [storyData, setStoryData] = useState<InteractiveStoryData | null>(null);
    const [layout, setLayout] = useState<ActiveComponent[]>([]);
    const [isGenerating, setIsGenerating] = useState(false);
    const [isPrinting, setIsPrinting] = useState(false);
    const [selectedId, setSelectedId] = useState<string | null>(null);

    const handleGenerate = async () => {
        setIsGenerating(true);
        try {
            const data = await generateInteractiveStory(config);
            setStoryData(data);

            // Auto-populate layout
            const newLayout: ActiveComponent[] = [];
            let currentY = 20;

            const add = (defId: string, h: number = 200) => {
                const def = AVAILABLE_COMPONENTS.find(c => c.id === defId);
                if (def) {
                    newLayout.push({
                        ...def,
                        instanceId: `${def.id}-${Date.now()}-${Math.random()}`,
                        style: { ...DEFAULT_STYLE_BASE, y: currentY, h: h },
                        isVisible: true
                    });
                    currentY += h + 20;
                }
            };

            add('header', 120);
            add('story_block', config.length === 'short' ? 300 : config.length === 'medium' ? 450 : 600);
            if (config.focusVocabulary) add('vocabulary', 200);
            if (config.include5N1K) add('questions_5n1k', 350);
            if (config.countMultipleChoice > 0 || config.countTrueFalse > 0) add('questions_test', 400);
            if (config.includeCreativeTask) add('creative', 250);

            setLayout(newLayout);

        } catch (e) {
            console.error(e);
            alert("Hikaye oluşturulamadı.");
        } finally {
            setIsGenerating(false);
        }
    };

    const addComponent = (def: ComponentDefinition) => {
        const newId = `${def.id}-${Date.now()}`;

        // --- SMART PLACEMENT LOGIC ---
        // Find the bottom-most edge of existing components to place the new one below
        let nextY = 20;
        const gap = 15;

        if (layout.length > 0) {
            // Calculate max(y + height) of all current items
            const maxY = Math.max(...layout.map(item => item.style.y + item.style.h));
            nextY = maxY + gap;
        }

        const newItem: ActiveComponent = { 
            ...def, 
            instanceId: newId, 
            style: { 
                ...DEFAULT_STYLE_BASE, 
                ...def.defaultStyle, 
                x: 0, 
                y: nextY 
            }, 
            isVisible: true, 
            customTitle: def.defaultTitle, 
            themeColor: 'black', 
            specificData: null 
        };
        setLayout(prev => [...prev, newItem]);
        setSelectedId(newId);
    };

    const handlePrint = async () => {
        setIsPrinting(true);
        setTimeout(async () => {
            try {
                await printService.generatePdf('#reading-canvas', config.topic, { action: 'print' });
            } catch (e) {
                console.error(e);
                alert("Yazdırma hatası oluştu.");
            } finally {
                setIsPrinting(false);
            }
        }, 500);
    };

    const handleSave = () => {
        if (!user || !storyData) return;
        if (onAddToWorkbook) {
            onAddToWorkbook({
                layout,
                storyData,
                config,
                title: config.topic
            });
        }
    };

