    const newId = `${def.id}-${Date.now()}`;

    // --- SMART PLACEMENT LOGIC ---
    // Find the bottom-most edge of existing components to place the new one below
    let nextY = 20;
    const gap = 15;

    if (layout.length > 0) {
        // Calculate max(y + height) of all current items
        const maxY = Math.max(...layout.map(item => item.style.y + item.style.h));
        nextY = maxY + gap;
    }

    const newItem: ActiveComponent = { 
