export interface ActiveComponent extends ComponentDefinition {
    instanceId: string;
    style: any; // Using any for layout style object (x, y, w, h etc)
    isVisible: boolean;
    customTitle?: string;
    content?: any;
    themeColor?: string;
    specificData?: any;
}

