    { id: 'header', label: 'Başlık Alanı', icon: 'fa-heading', type: 'header', defaultTitle: 'Okuma Parçası', defaultStyle: { h: 80 } },
    { id: 'text_block', label: 'Metin Bloğu', icon: 'fa-align-left', type: 'text', defaultTitle: 'Hikaye Metni', defaultStyle: { h: 300 } },
    { id: 'image_block', label: 'Görsel', icon: 'fa-image', type: 'image', defaultTitle: 'Görsel', defaultStyle: { h: 200, w: 200 } },
