interface ReadingStudioProps {
    onBack: () => void;
    onAddToWorkbook?: (data: any) => void;
}

export const ReadingStudio: React.FC<ReadingStudioProps> = ({ onBack, onAddToWorkbook }) => {
    const { user } = useAuth();
    const [layout, setLayout] = useState<ActiveComponent[]>([]);
    const [selectedId, setSelectedId] = useState<string | null>(null);
    const [pageTitle, setPageTitle] = useState('Okuma Çalışması');

    // Actions state
    const [isSaving, setIsSaving] = useState(false);
    const [isPrinting, setIsPrinting] = useState(false);
    const [isShareModalOpen, setIsShareModalOpen] = useState(false);

    const addComponent = (def: ComponentDefinition) => {
        const newId = `${def.id}-${Date.now()}`;

        let nextY = 20;
        const gap = 15;

        if (layout.length > 0) {
            const maxY = Math.max(...layout.map(item => (item.style.y || 0) + (item.style.h || 100)));
            nextY = maxY + gap;
        }

        const newItem: ActiveComponent = { 
            ...def, 
            instanceId: newId, 
            style: { 
                ...DEFAULT_STYLE_BASE, 
                ...def.defaultStyle, 
                x: 40, // Left margin approx
                y: nextY 
            }, 
            isVisible: true, 
            customTitle: def.defaultTitle, 
            themeColor: 'black', 
            specificData: null 
        };
        setLayout(prev => [...prev, newItem]);
        setSelectedId(newId);
    };

    const removeComponent = (id: string) => {
        setLayout(prev => prev.filter(c => c.instanceId !== id));
        if (selectedId === id) setSelectedId(null);
    };

    const updateComponent = (id: string, updates: Partial<ActiveComponent>) => {
        setLayout(prev => prev.map(c => c.instanceId === id ? { ...c, ...updates } : c));
    };

    const handleSave = async () => {
        if (!user) { alert("Giriş yapmalısınız."); return; }
        setIsSaving(true);
        try {
            await worksheetService.saveWorksheet(
                user.id,
                pageTitle,
                'STORY_COMPREHENSION', // Use compatible type or create new 'READING_STUDIO'
                [{ layout, pageTitle, isStudio: true }], // Save layout data structure
                'fa-solid fa-book-open-reader',
                { id: 'reading-verbal', title: 'Okuma & Dil' }
            );
            alert("Kaydedildi.");
        } catch (e) {
            console.error(e);
            alert("Hata oluştu.");
        } finally {
            setIsSaving(false);
        }
    };

    const handlePrint = async (action: 'print' | 'download') => {
        setIsPrinting(true);
        try {
            await printService.generatePdf('#reading-canvas', pageTitle, { action });
        } finally {
            setIsPrinting(false);
        }
    };

    const handleShare = async (receiverId: string) => {
        if (!user) return;
        try {
            const mockSavedWorksheet: any = {
                name: pageTitle,
                activityType: 'STORY_COMPREHENSION',
                worksheetData: [{ layout, pageTitle, isStudio: true }],
                icon: 'fa-solid fa-book-open-reader',
                category: { id: 'reading-verbal', title: 'Okuma & Dil' }
            };
            await worksheetService.shareWorksheet(mockSavedWorksheet, user.id, user.name, receiverId);
            setIsShareModalOpen(false);
            alert("Paylaşıldı.");
        } catch (e) {
            alert("Paylaşım hatası.");
        }
    };

    return (
        <div className="h-full flex flex-col bg-[#121212] text-white font-sans overflow-hidden">
            {/* Header */}
            <div className="h-16 bg-[#18181b] border-b border-zinc-800 flex justify-between items-center px-6 shrink-0 z-50">
                 <div className="flex items-center gap-4">
                    <button onClick={onBack} className="w-10 h-10 rounded-full bg-zinc-800 hover:bg-zinc-700 flex items-center justify-center text-zinc-400 transition-colors"><i className="fa-solid fa-arrow-left"></i></button>
                    <h1 className="font-black text-xl tracking-tight text-white flex items-center gap-2">
                        <span className="text-transparent bg-clip-text bg-gradient-to-r from-emerald-400 to-teal-500">READING STUDIO</span>
                    </h1>
                </div>
                <div className="flex gap-2">
                     <button onClick={() => handlePrint('download')} disabled={isPrinting} className="p-2 text-zinc-400 hover:text-white"><i className="fa-solid fa-file-pdf"></i></button>
                     <button onClick={() => handlePrint('print')} disabled={isPrinting} className="p-2 text-zinc-400 hover:text-white"><i className="fa-solid fa-print"></i></button>
                     <button onClick={() => setIsShareModalOpen(true)} className="p-2 text-zinc-400 hover:text-white"><i className="fa-solid fa-share-nodes"></i></button>
