            <div className="flex border-b border-zinc-700 bg-[#222226] shrink-0">
                {[
                    { id: 'content', icon: 'fa-pen-to-square', label: 'İçerik' },
                    { id: 'type', icon: 'fa-font', label: 'Yazı' },
                    { id: 'look', icon: 'fa-palette', label: 'Stil' },
