                                                             <div className="absolute inset-0" style={{transform: 'scale(0.15)', transformOrigin: '0 0', width: '600%', height: '600%'}}>
                                                                 {t.layout.map((item, idx) => (
                                                                     <div key={idx} style={{
                                                                         position: 'absolute',
                                                                         left: item.style.x,
                                                                         top: item.style.y,
                                                                         width: item.style.w,
                                                                         height: item.style.h,
