                                                                         position: 'absolute',
                                                                         left: item.style.x,
                                                                         top: item.style.y,
                                                                         width: item.style.w,
                                                                         height: item.style.h,
                                                                         border: '2px solid #ccc',
                                                                         backgroundColor: item.style.backgroundColor || 'transparent'
                                                                     }}></div>
                                                                 ))}
                                                             </div>
                                                         </div>
                                                     </div>
                                                 ))}
                                             </div>
                                         )}
                                     </div>
                                 </div>
                             )}
