import React, { useState, useRef, useEffect, useCallback, useMemo, useLayoutEffect } from 'react';
import { InteractiveStoryData, LayoutSectionId, LayoutItem, ReadingStudioConfig, ActivityType } from '../../types';
import { generateInteractiveStory } from '../../services/generators/readingStudio';
import { useAuth } from '../../context/AuthContext';
import { printService } from '../../utils/printService';
import { worksheetService } from '../../services/worksheetService';
import { ImageDisplay, QUESTION_TYPES, StoryHighlighter } from '../sheets/common';
import { EditableText } from '../Editable';
import { ShareModal } from '../ShareModal';

// --- CONFIGURATION CONSTANTS ---
const SNAP_GRID = 5; 
const A4_WIDTH_PX = 794; 
const A4_HEIGHT_PX = 1123; 
const PAGE_BOTTOM_PADDING = 100; 
const VERTICAL_GAP = 15; // Bileşenler arası standart boşluk

// --- DEFINITIONS ---

interface ComponentDefinition {
    id: LayoutSectionId;
    label: string;
    defaultTitle: string;
    icon: string;
    description: string;
    defaultStyle: Partial<LayoutItem['style']>;
}

interface ActiveComponent extends LayoutItem {
    customTitle?: string;
    customIcon?: string;
    themeColor?: string;
    instanceId: string;
}

interface SavedTemplate {
    id: string;
    name: string;
    createdAt: string;
    layout: ActiveComponent[];
}

const DEFAULT_STYLE_BASE: LayoutItem['style'] = {
    x: 20, y: 20, w: 754, h: 100, zIndex: 1, rotation: 0,
    padding: 10,
    backgroundColor: 'transparent',
    borderColor: 'transparent',
    borderWidth: 0,
    borderStyle: 'solid',
    borderRadius: 0,
    opacity: 1,
    boxShadow: 'none',
    textAlign: 'left',
    color: '#000000',
    fontSize: 14,
    fontFamily: 'OpenDyslexic',
    lineHeight: 1.5,
    letterSpacing: 0,
    imageSettings: {
        enabled: true,
        position: 'right',
        widthPercent: 40,
        opacity: 1,
        objectFit: 'cover',
        borderRadius: 8,
        blendMode: 'normal',
        filter: 'none'
    }
};

const COMPONENT_DEFINITIONS: ComponentDefinition[] = [
    { id: 'header', label: 'Başlık Künyesi', defaultTitle: 'HİKAYE KÜNYESİ', icon: 'fa-heading', description: 'Başlık ve tarih alanı.', defaultStyle: { h: 120 } },
    { id: 'tracker', label: 'Okuma Takipçisi', defaultTitle: 'OKUMA TAKİBİ', icon: 'fa-eye', description: 'Yıldızlı okuma takip alanı.', defaultStyle: { h: 60, w: 200 } },
    { id: 'story_block', label: 'Hikaye Metni', defaultTitle: 'OKUMA METNİ', icon: 'fa-book-open', description: 'Ana hikaye ve görsel bloğu.', defaultStyle: { h: 400 } },
    { id: 'vocabulary', label: 'Sözlükçe', defaultTitle: 'SÖZLÜKÇE', icon: 'fa-spell-check', description: 'Kelime ve anlam listesi.', defaultStyle: { h: 150 } },
    { id: 'questions_5n1k', label: '5N 1K Analizi', defaultTitle: '5N 1K SORULARI', icon: 'fa-circle-question', description: 'Analitik sorular.', defaultStyle: { h: 300 } },
    { id: 'questions_test', label: 'Test Soruları', defaultTitle: 'DEĞERLENDİRME', icon: 'fa-list-check', description: 'Çoktan seçmeli.', defaultStyle: { h: 300 } },
    { id: 'questions_inference', label: 'Derin Analiz', defaultTitle: 'DERİN ANALİZ', icon: 'fa-brain', description: 'Yorumlama soruları.', defaultStyle: { h: 150 } },
    { id: 'creative', label: 'Yaratıcı Alan', defaultTitle: 'YARATICI ALAN', icon: 'fa-paintbrush', description: 'Çizim ve hayal gücü.', defaultStyle: { h: 200 } },
    { id: 'notes', label: 'Not Alanı', defaultTitle: 'NOTLAR', icon: 'fa-note-sticky', description: 'Öğretmen/Veli notları.', defaultStyle: { h: 100 } },
];

const AutoContentWrapper = ({ 
    children, 
    onSizeChange,
    isActive 
}: { 
    children?: React.ReactNode, 
    onSizeChange: (w: number, h: number) => void,
    isActive: boolean
}) => {
    const ref = useRef<HTMLDivElement>(null);
    const lastReportedHeight = useRef<number>(0);

    useLayoutEffect(() => {
        if (!ref.current) return;

        const observer = new ResizeObserver((entries) => {
            for (const entry of entries) {
                const contentHeight = entry.target.scrollHeight;
                const width = entry.contentRect.width;

                if (Math.abs(contentHeight - lastReportedHeight.current) > 2) {
                     lastReportedHeight.current = contentHeight;
                     onSizeChange(width, contentHeight);
                }
            }
        });

        observer.observe(ref.current);
        return () => observer.disconnect();
    }, [onSizeChange]);

    return (
        <div 
            ref={ref} 
            className="w-full"
            style={{ height: 'auto', minHeight: '100%', overflow: 'visible' }}
        >
            {children}
        </div>
    );
};

const ResizeHandle = ({ cursor, position, onMouseDown }: { cursor: string, position: string, onMouseDown: (e: React.MouseEvent) => void }) => (
    <div 
        className={`absolute w-3 h-3 bg-indigo-500 border border-white rounded-full z-50 hover:scale-150 transition-transform ${position}`}
        style={{ cursor }}
        onMouseDown={(e) => { e.stopPropagation(); onMouseDown(e); }}
    />
);

const RotateHandle = ({ onMouseDown }: { onMouseDown: (e: React.MouseEvent) => void }) => (
    <div 
        className="absolute -top-8 left-1/2 -translate-x-1/2 w-6 h-6 bg-zinc-800 border border-indigo-500 rounded-full z-50 hover:bg-indigo-500 hover:text-white text-indigo-500 flex items-center justify-center cursor-alias shadow-sm transition-all"
        onMouseDown={(e) => { e.stopPropagation(); onMouseDown(e); }}
        title="Döndür"
    >
        <i className="fa-solid fa-rotate text-[10px]"></i>
    </div>
);

// --- MAIN READING STUDIO COMPONENT ---

interface ReadingStudioProps {
    onBack: () => void;
    onAddToWorkbook?: (data: any) => void;
}

export const ReadingStudio: React.FC<ReadingStudioProps> = ({ onBack, onAddToWorkbook }) => {
    const { user } = useAuth();
    const [isLoading, setIsLoading] = useState(false);
    const [isSaving, setIsSaving] = useState(false);
    const [isSaved, setIsSaved] = useState(false);
    const [isShareModalOpen, setIsShareModalOpen] = useState(false);

    const [storyData, setStoryData] = useState<InteractiveStoryData | null>(null);
    const [sidebarTab, setSidebarTab] = useState<'settings' | 'library' | 'templates'>('settings');
    const [layout, setLayout] = useState<ActiveComponent[]>([]);
    const [selectedId, setSelectedId] = useState<string | null>(null);
    const [designMode, setDesignMode] = useState(true);

    const [config, setConfig] = useState<ReadingStudioConfig>({
        gradeLevel: '3. Sınıf', studentName: '', topic: '', genre: 'Macera', tone: 'Eğlenceli',
        length: 'medium', layoutDensity: 'comfortable', textComplexity: 'moderate',
        fontSettings: { family: 'OpenDyslexic', size: 16, lineHeight: 1.8, letterSpacing: 1, wordSpacing: 2 },
        includeImage: true, imageSize: 40, imageOpacity: 100, imagePosition: 'right',
        imageGeneration: { enabled: true, style: 'storybook', complexity: 'simple' },
        include5N1K: true, countMultipleChoice: 3, countTrueFalse: 2, countFillBlanks: 2, countLogic: 1, countInference: 1, 
        focusVocabulary: true, includeCreativeTask: true, includeWordHunt: false, includeSpellingCheck: false,
        showReadingTracker: false, showSelfAssessment: false, showTeacherNotes: false, showDateSection: true
    });

    const [templates, setTemplates] = useState<SavedTemplate[]>([]);
    const [isSidebarOpen, setIsSidebarOpen] = useState(true);

    const [canvasScale, setCanvasScale] = useState(0.85);
    const [canvasPos, setCanvasPos] = useState({ x: 0, y: 40 }); 
    const [isPanning, setIsPanning] = useState(false);
    const lastMousePos = useRef({ x: 0, y: 0 });
    const canvasRef = useRef<HTMLDivElement>(null);

    const [dragState, setDragState] = useState<{ mode: 'drag' | 'resize' | 'rotate'; resizeHandle?: string; startX: number; startY: number; initialX: number; initialY: number; initialW: number; initialH: number; initialR: number; centerX?: number; centerY?: number; } | null>(null);

    // --- DİNAMİK YÜKSEKLİK HESAPLAMA ---
    const contentHeight = useMemo(() => {
        if (layout.length === 0) return A4_HEIGHT_PX;
        const visibleItems = layout.filter(l => l.isVisible);
        if (visibleItems.length === 0) return A4_HEIGHT_PX;
        const maxY = Math.max(...visibleItems.map(item => item.style.y + item.style.h));
        return Math.max(A4_HEIGHT_PX, maxY + PAGE_BOTTOM_PADDING);
    }, [layout]);

    // --- AKILLI MİZANPAJ MOTORU (SMART RE-FLOW) ---
    const handleAutoResize = useCallback((instanceId: string, newContentHeight: number) => {
        setLayout(prevLayout => {
            const itemIndex = prevLayout.findIndex(item => item.instanceId === instanceId);
            if (itemIndex === -1) return prevLayout;

            const item = prevLayout[itemIndex];
            const oldHeight = item.style.h;
            const roundedNewHeight = Math.ceil(newContentHeight / SNAP_GRID) * SNAP_GRID;

            // Sonsuz döngüyü önlemek için eşik değeri
            if (Math.abs(oldHeight - roundedNewHeight) < 5) return prevLayout;

            const deltaY = roundedNewHeight - oldHeight;
            const itemBottomY = item.style.y + oldHeight;

            const newLayout = [...prevLayout];
            newLayout[itemIndex] = {
                ...item,
                style: { ...item.style, h: roundedNewHeight }
            };

            // ALTAKİ TÜM BİLEŞENLERİ İT VEYA ÇEK
            for (let i = 0; i < newLayout.length; i++) {
                if (i === itemIndex) continue;
                // Sadece mevcut bileşenin altında başlayanları etkile
                if (newLayout[i].style.y >= (itemBottomY - 10)) {
                    newLayout[i] = {
                        ...newLayout[i],
                        style: {
                            ...newLayout[i].style,
                            y: Math.max(20, newLayout[i].style.y + deltaY)
                        }
                    };
                }
            }

            return newLayout;
        });
    }, []);

    const addComponent = (def: ComponentDefinition) => {
        const newId = `${def.id}-${Date.now()}-${Math.random().toString(36).substr(2, 4)}`;
        const visibleItems = layout.filter(l => l.isVisible);

        let nextY = 20; 
        if (visibleItems.length > 0) {
            const maxY = Math.max(...visibleItems.map(item => item.style.y + item.style.h));
            nextY = maxY + VERTICAL_GAP;
        }

        const newItem: ActiveComponent = { 
            ...def, 
            instanceId: newId, 
            style: { 
                ...DEFAULT_STYLE_BASE, 
                ...def.defaultStyle, 
                x: 20, 
                y: nextY,
                w: 754,
                zIndex: layout.length + 1
            }, 
            isVisible: true, 
            customTitle: def.defaultTitle, 
            themeColor: 'black', 
            specificData: null 
        };
        setLayout(prev => [...prev, newItem]);
        setSelectedId(newId);
        setIsSaved(false);
    };

    const removeComponent = (id: string) => {
        if(!confirm("Bu bileşeni silmek istediğinize emin misiniz?")) return;

        setLayout(prev => {
            const itemToRemove = prev.find(item => item.instanceId === id);
            if (!itemToRemove) return prev;

            const removedHeight = itemToRemove.style.h + VERTICAL_GAP;
            const removedY = itemToRemove.style.y;

            const filtered = prev.filter(item => item.instanceId !== id);

            // Altındakileri yukarı çek
            return filtered.map(item => {
                if (item.style.y > removedY) {
                    return { ...item, style: { ...item.style, y: Math.max(20, item.style.y - removedHeight) } };
                }
                return item;
            });
        });

        if(selectedId === id) setSelectedId(null);
        setIsSaved(false);
    };

    const toggleVisibility = (id: string) => {
        setLayout(prev => {
            const item = prev.find(i => i.instanceId === id);
            if (!item) return prev;

            const isClosing = item.isVisible;
            const itemHeight = item.style.h + VERTICAL_GAP;
            const deltaY = isClosing ? -itemHeight : itemHeight;

            return prev.map(l => {
                if (l.instanceId === id) return { ...l, isVisible: !l.isVisible };
                // Sadece altındakileri kaydır
                if (l.style.y > item.style.y) {
                    return { ...l, style: { ...l.style, y: Math.max(20, l.style.y + deltaY) } };
                }
                return l;
            });
        });
        setIsSaved(false);
    };

    // --- CANVAS INTERACTIONS ---
    const handleCanvasWheel = useCallback((e: React.WheelEvent) => {
        if (e.ctrlKey) e.preventDefault();
        const zoomSensitivity = -0.001; 
        const delta = e.deltaY * zoomSensitivity;
        const newScale = Math.min(Math.max(0.2, canvasScale + delta), 4);
        setCanvasScale(newScale);
    }, [canvasScale]);

    const handleMouseDown = (e: React.MouseEvent, id: string, mode: 'drag' | 'resize' | 'rotate' = 'drag', handle?: string) => {
        if (!designMode) return;
        e.stopPropagation();
        const item = layout.find(l => l.instanceId === id);
        if (!item) return;
        setSelectedId(id);

        let centerX = 0; let centerY = 0;
        if (mode === 'rotate') {
             const element = e.currentTarget.parentElement; 
             if (element) {
                 const rect = element.getBoundingClientRect();
                 centerX = rect.left + rect.width / 2;
                 centerY = rect.top + rect.height / 2;
             }
        }

        setDragState({ mode, resizeHandle: handle, startX: e.clientX, startY: e.clientY, initialX: item.style.x, initialY: item.style.y, initialW: item.style.w, initialH: item.style.h, initialR: item.style.rotation || 0, centerX, centerY });
    };

    useEffect(() => {
        const handleMouseMove = (e: MouseEvent) => {
            if (isPanning) {
                const dx = e.clientX - lastMousePos.current.x;
                setCanvasPos(prev => ({ x: prev.x + dx, y: prev.y }));
                lastMousePos.current = { x: e.clientX, y: e.clientY };
                return;
            }
            if (!dragState || !selectedId) return;

            const dx = (e.clientX - dragState.startX) / canvasScale;
            const dy = (e.clientY - dragState.startY) / canvasScale;
            const snap = (val: number) => Math.round(val / SNAP_GRID) * SNAP_GRID;

            setLayout(prev => {
                const item = prev.find(l => l.instanceId === selectedId);
                if (!item) return prev;

                let newStyle = { ...item.style };
                let itemHeightDelta = 0;

                if (dragState.mode === 'drag') {
                    // Dikey kaydırmada x'i 20'de sabitleyebiliriz (opsiyonel)
                    newStyle.x = snap(dragState.initialX + dx);
                    newStyle.y = snap(dragState.initialY + dy);
                } else if (dragState.mode === 'resize' && dragState.resizeHandle) {
                    const h = dragState.resizeHandle;
                    if (h.includes('e')) newStyle.w = Math.max(50, snap(dragState.initialW + dx));
                    if (h.includes('s')) {
                        const nextH = Math.max(50, snap(dragState.initialH + dy));
                        itemHeightDelta = nextH - item.style.h;
                        newStyle.h = nextH;
                    }
                }

                // EĞER BOYUT DEĞİŞTİYSE ALTAKİLERİ İT
                return prev.map(l => {
                    if (l.instanceId === selectedId) return { ...l, style: newStyle };
                    if (itemHeightDelta !== 0 && l.style.y >= (item.style.y + item.style.h - 5)) {
                        return { ...l, style: { ...l.style, y: Math.max(20, l.style.y + itemHeightDelta) } };
                    }
                    return l;
                });
            });
        };
        const handleMouseUp = () => { setDragState(null); setIsPanning(false); };
        if (dragState || isPanning) { window.addEventListener('mousemove', handleMouseMove); window.addEventListener('mouseup', handleMouseUp); }
        return () => { window.removeEventListener('mousemove', handleMouseMove); window.removeEventListener('mouseup', handleMouseUp); };
    }, [dragState, selectedId, isPanning, canvasScale]);

    const handlePrint = async (action: 'print' | 'download') => {
        const prevMode = designMode;
        setDesignMode(false);
        setSelectedId(null);
        setTimeout(async () => { 
            await printService.generatePdf('#canvas-root', storyData?.title || 'Okuma Calismasi', { action }); 
            setDesignMode(prevMode); 
        }, 300);
    };

    const renderContent = (item: ActiveComponent) => {
        const s = item.style;
        const boxStyle = {
            padding: `${s.padding}px`,
            backgroundColor: s.backgroundColor,
            borderColor: s.borderColor,
            borderWidth: `${s.borderWidth}px`,
            borderStyle: s.borderStyle || 'solid',
            borderRadius: `${s.borderRadius}px`,
            boxShadow: s.boxShadow !== 'none' ? `var(--shadow-${s.boxShadow})` : 'none',
            opacity: s.opacity,
            color: s.color,
            fontFamily: s.fontFamily,
            fontSize: `${s.fontSize}px`,
            lineHeight: s.lineHeight,
            textAlign: s.textAlign as any,
            letterSpacing: `${s.letterSpacing}px`,
            fontWeight: s.fontWeight || 'normal'
        };

        if (item.id === 'header') {
            const data = item.specificData || { title: "HİKAYE BAŞLIĞI", subtitle: `Tarih: ....................` };
            return (
                <div className="h-full flex flex-col justify-end" style={boxStyle}>
                    <h1 className="font-black uppercase leading-none tracking-tight" style={{fontSize: '2.5em', color: 'inherit'}}>{data.title}</h1>
                    <div className="flex justify-between items-end mt-2 opacity-70">
                        <span className="font-mono text-sm">{data.subtitle}</span>
                    </div>
                </div>
            );
        }

        if (item.id === 'story_block') {
            const data = item.specificData || { text: "Hikaye metni bekleniyor...", imagePrompt: "" };
            return (
                <AutoContentWrapper isActive={designMode} onSizeChange={(w, h) => handleAutoResize(item.instanceId, h)}>
                    <div className="relative overflow-hidden" style={{ ...boxStyle, height: 'auto', minHeight: '100%' }}>
                         {item.style.imageSettings?.enabled && (
                            <div className={`float-${item.style.imageSettings.position === 'left' ? 'left' : 'right'} w-1/3 h-48 bg-transparent ml-4 mb-2 rounded-lg relative z-10`}>
                                <ImageDisplay prompt={data.imagePrompt} description="Hikaye Görseli" className="w-full h-full object-contain" />
                            </div>
                         )}
                         <div dangerouslySetInnerHTML={{__html: (data.text || '').replace(/\n/g, '<br/>')}}></div>
                    </div>
                </AutoContentWrapper>
            );
        }

        if (item.id.startsWith('questions')) {
            const data = item.specificData || { questions: [{text: "Soru 1..."}] };
            return (
                <AutoContentWrapper isActive={designMode} onSizeChange={(w, h) => handleAutoResize(item.instanceId, h)}>
                <div className="flex flex-col" style={{ ...boxStyle, height: 'auto', minHeight: '100%' }}>
                    <h4 className="font-black text-xs uppercase mb-2 border-b pb-1 opacity-50">{item.customTitle}</h4>
                    <div className="flex-1 space-y-3">
                        {(data.questions || []).map((q: any, i: number) => (
                            <div key={i} className="flex gap-3 items-start border-b border-zinc-100 pb-2">
                                <span className="font-bold bg-zinc-900 text-white w-6 h-6 rounded flex items-center justify-center text-[10px] shrink-0" style={{backgroundColor: s.color, color: 'white'}}>{i+1}</span>
                                <p className="leading-snug pt-0.5">{q.text}</p>
                            </div>
                        ))}
                    </div>
                </div>
                </AutoContentWrapper>
            );
        }

        // Diğer bileşenler için varsayılan görünüm
        return (
             <div className="h-full flex items-center justify-center border-2 border-dashed border-zinc-200 rounded" style={boxStyle}>
                 <span className="opacity-30 font-bold uppercase text-xs">{item.label}</span>
             </div>
        );
    };

    return (
        <div className="h-full flex flex-col bg-[#1a1a1c] font-['OpenDyslexic'] overflow-hidden text-zinc-100">
            {/* Top Bar */}
            <div className="h-14 bg-[#2d2d32] border-b border-zinc-800 flex justify-between items-center px-4 shrink-0 z-50 shadow-md">
                <div className="flex items-center gap-3">
                    <button onClick={onBack} className="w-8 h-8 rounded-lg hover:bg-zinc-700 flex items-center justify-center text-zinc-400"><i className="fa-solid fa-arrow-left"></i></button>
                    <span className="font-black text-sm uppercase tracking-widest text-indigo-400 flex items-center gap-2">Reading Studio <span className="bg-indigo-500/20 text-[9px] px-1 rounded border border-indigo-500/50">PRO</span></span>
                </div>
                <div className="flex items-center gap-3">
                     <button onClick={() => setDesignMode(!designMode)} className={`px-4 py-1.5 rounded-full text-[10px] font-black tracking-widest border transition-all ${designMode ? 'bg-indigo-50 text-white border-indigo-400' : 'bg-zinc-800 border-zinc-700 text-zinc-400 hover:text-white'}`}>
                         {designMode ? 'MİMARİ MOD' : 'ÖNİZLEME'}
                     </button>
                     <div className="h-6 w-px bg-zinc-800 mx-1"></div>
                     <button onClick={() => handlePrint('print')} className="w-8 h-8 rounded-lg hover:bg-zinc-700 flex items-center justify-center text-zinc-400" title="Yazdır"><i className="fa-solid fa-print"></i></button>
                     <button onClick={() => setIsShareModalOpen(true)} className="w-8 h-8 rounded-lg hover:bg-zinc-700 flex items-center justify-center text-zinc-400" title="Paylaş"><i className="fa-solid fa-share-nodes"></i></button>
                </div>
            </div>

            <div className="flex-1 flex overflow-hidden relative">
                {/* Left Sidebar: Component Library */}
                <div className={`flex-shrink-0 h-full bg-[#18181b] border-r border-zinc-800 transition-all duration-300 overflow-hidden z-40 ${isSidebarOpen ? 'w-72' : 'w-0'}`}>
                    <div className="w-72 flex flex-col h-full">
                         <div className="p-4 border-b border-zinc-800">
                             <h4 className="text-[10px] font-black text-zinc-500 uppercase tracking-widest mb-4">KÜTÜPHANE</h4>
                             <div className="grid grid-cols-2 gap-2">
                                 {COMPONENT_DEFINITIONS.map(def => (
                                     <button key={def.id} onClick={() => addComponent(def)} className="flex flex-col items-center gap-2 p-3 bg-zinc-800/50 border border-zinc-700 rounded-xl hover:border-indigo-500 transition-all group">
                                         <i className={`fa-solid ${def.icon} text-zinc-500 group-hover:text-indigo-400 text-lg`}></i>
                                         <span className="text-[9px] font-bold text-zinc-400 group-hover:text-white text-center leading-tight uppercase">{def.label}</span>
                                     </button>
                                 ))}
                             </div>
                         </div>
                         <div className="flex-1 overflow-y-auto p-2 custom-scrollbar">
                             <h4 className="text-[10px] font-black text-zinc-500 uppercase tracking-widest p-2">KATMANLAR</h4>
                             {layout.map(item => (
                                 <div key={item.instanceId} onClick={() => setSelectedId(item.instanceId)} className={`flex items-center gap-3 p-2 rounded-lg cursor-pointer transition-all ${selectedId === item.instanceId ? 'bg-indigo-600/20 border border-indigo-500/50' : 'hover:bg-zinc-800 border border-transparent'}`}>
                                     <div className="w-6 h-6 rounded bg-zinc-900 flex items-center justify-center text-[10px] text-indigo-400"><i className={`fa-solid ${item.icon}`}></i></div>
                                     <span className="text-[11px] font-bold truncate flex-1">{item.customTitle || item.label}</span>
                                     <button onClick={(e) => { e.stopPropagation(); toggleVisibility(item.instanceId); }} className="text-zinc-600 hover:text-indigo-400"><i className={`fa-solid ${item.isVisible ? 'fa-eye' : 'fa-eye-slash'}`}></i></button>
                                     <button onClick={(e) => { e.stopPropagation(); removeComponent(item.instanceId); }} className="text-zinc-600 hover:text-red-500"><i className="fa-solid fa-trash"></i></button>
                                 </div>
                             ))}
                         </div>
                    </div>
                </div>

                <button onClick={() => setIsSidebarOpen(!isSidebarOpen)} className="absolute left-0 top-1/2 -translate-y-1/2 z-50 w-4 h-12 bg-zinc-800 border border-zinc-700 rounded-r-lg flex items-center justify-center text-[8px] text-zinc-500 hover:text-indigo-400 transition-all shadow-xl">
                    <i className={`fa-solid fa-chevron-${isSidebarOpen ? 'left' : 'right'}`}></i>
                </button>

                {/* Main Canvas Area */}
                <div 
                    ref={canvasRef}
                    className="flex-1 bg-[#121214] overflow-auto flex justify-center p-12 bg-[url('https://www.transparenttextures.com/patterns/cubes.png')] custom-scrollbar"
                    onWheel={handleCanvasWheel}
                >
                    <div 
                        className="origin-top transition-transform duration-75 shadow-2xl"
                        style={{ transform: `scale(${canvasScale})` }}
                    >
                        <div 
                            id="canvas-root" 
                            className="bg-white relative transition-all duration-300" 
                            style={{ 
                                width: `${A4_WIDTH_PX}px`, 
                                height: `${contentHeight}px`,
                                padding: '40px' 
                            }}
                        >
                            {layout.filter(l => l.isVisible).map((item) => (
                                <div 
                                    key={item.instanceId} 
                                    onMouseDown={(e) => handleMouseDown(e, item.instanceId, 'drag')} 
                                    className={`absolute ${designMode ? 'hover:ring-1 hover:ring-indigo-500 cursor-move' : ''}`} 
                                    style={{ left: item.style.x, top: item.style.y, width: item.style.w, height: item.style.h, zIndex: item.style.zIndex }}
                                >
                                    {designMode && selectedId === item.instanceId && (
                                        <div className="absolute inset-0 border-2 border-indigo-500 z-50 pointer-events-none">
                                            <div className="pointer-events-auto"><ResizeHandle cursor="s-resize" position="-bottom-1.5 left-1/2 -translate-x-1/2" onMouseDown={(e) => handleMouseDown(e, item.instanceId, 'resize', 's')} /></div>
                                        </div>
                                    )}
                                    <div className="w-full h-full overflow-visible pointer-events-none text-black">{renderContent(item)}</div>
                                </div>
                            ))}

                            {/* Page Info */}
                            <div className="absolute bottom-4 left-0 w-full text-center text-[10px] text-zinc-300 font-mono pointer-events-none px-8 flex justify-between">
                                <span>Bursa Disleksi AI © {new Date().getFullYear()}</span>
                                <span>Sayfa 1</span>
                            </div>
                        </div>
                    </div>
                </div>
            </div>

            <ShareModal isOpen={isShareModalOpen} onClose={() => setIsShareModalOpen(false)} onShare={() => {}} />
        </div>
    );
};

